import { getToken } from "next-auth/jwt";
import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";

// Simple in-memory rate limiter (Token Bucket-ish)
const rateLimitMap = new Map<string, { count: number, lastReset: number }>();
const WINDOW_SIZE = 60 * 1000; // 1 minute
const MAX_REQUESTS = 100; // 100 requests per minute

function isRateLimited(ip: string): boolean {
    const now = Date.now();
    const bucket = rateLimitMap.get(ip) || { count: 0, lastReset: now };

    if (now - bucket.lastReset > WINDOW_SIZE) {
        bucket.count = 0;
        bucket.lastReset = now;
    }

    if (bucket.count >= MAX_REQUESTS) {
        return true;
    }

    bucket.count++;
    rateLimitMap.set(ip, bucket);

    // Cleanup old entries periodically (simple optimization)
    if (rateLimitMap.size > 10000) rateLimitMap.clear();

    return false;
}

export async function middleware(req: NextRequest) {
    // @ts-ignore
    const ip = req.ip || req.headers.get("x-forwarded-for") || "unknown";

    // 1. Rate Limiting (Apply to API routes only)
    if (req.nextUrl.pathname.startsWith("/api")) {
        if (isRateLimited(ip)) {
            // Log the security event
            console.warn(JSON.stringify({ type: "RATE_LIMIT_EXCEEDED", ip, path: req.nextUrl.pathname }));
            return NextResponse.json({ error: "Too many requests" }, { status: 429 });
        }
    }

    // 2. Authorization Logic
    const token = await getToken({ req });
    const { pathname } = req.nextUrl;

    // Admin Routes
    if (pathname.startsWith("/admin")) {
        if (!token || token.role !== "ADMIN") {
            return NextResponse.redirect(new URL("/", req.url));
        }
    }

    // Authenticated Routes
    const authRoutes = [
        "/profile",
        "/messages",
        "/alliances/create",
        "/alliances/settings"
    ];

    if (authRoutes.some(route => pathname.startsWith(route))) {
        if (!token) {
            return NextResponse.redirect(new URL("/api/auth/signin", req.url));
        }
    }

    return NextResponse.next();
}

export const config = {
    matcher: [
        "/admin/:path*",
        "/profile/:path*",
        "/messages/:path*",
        "/alliances/create",
        "/alliances/settings/:path*",
        "/api/:path*" // Include ALL APIs for Rate Limiting
    ],
};

