"use client";

import { useEffect, useState } from "react";
import { useSession } from "next-auth/react";
import Link from "next/link";
import { useRouter } from "next/navigation";

export default function AdminBoards() {
    const { data: session } = useSession();
    const router = useRouter();
    const [boards, setBoards] = useState<any[]>([]);
    const [showModal, setShowModal] = useState(false);
    const [activeMenuId, setActiveMenuId] = useState<string | null>(null);

    const [editingId, setEditingId] = useState<string | null>(null);

    // Form State
    // Form State
    const [title, setTitle] = useState("");
    const [slug, setSlug] = useState("");
    const [availCats, setAvailCats] = useState("");
    const [desc, setDesc] = useState("");

    useEffect(() => {
        if (session?.user?.role !== "ADMIN") {
            return;
        }
        fetchBoards();
    }, [session]);

    const fetchBoards = () => {
        fetch("/api/board/list")
            .then(res => res.json())
            .then(data => {
                if (data.boards) setBoards(data.boards);
            });
    };

    const handleCreate = async (e: React.FormEvent) => {
        e.preventDefault();

        const categories = availCats.split(',').map(c => c.trim()).filter(c => c.length > 0);

        const url = editingId ? "/api/board/update" : "/api/board/create";
        const method = editingId ? "PUT" : "POST";
        const body = editingId
            ? { id: editingId, title, slug, availableCategories: categories, description: desc }
            : { title, slug, availableCategories: categories, description: desc };

        const res = await fetch(url, {
            method: method,
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(body)
        });

        if (res.ok) {
            setShowModal(false);
            fetchBoards();
            resetForm();
        } else {
            alert(editingId ? "Failed to update board." : "Failed to create board. Check slug uniqueness.");
        }
    };

    const resetForm = () => {
        setTitle("");
        setSlug("");
        setAvailCats("");
        setDesc("");
        setEditingId(null);
    }

    const openEdit = (board: any) => {
        setEditingId(board.id);
        setTitle(board.title);
        setSlug(board.slug);
        setAvailCats(board.availableCategories?.join(", ") || "");
        setDesc(board.description || "");
        setShowModal(true);
        setActiveMenuId(null);
    }

    // Delete Handler
    const handleDelete = async (boardId: string, boardTitle: string) => {
        if (confirm(`Are you sure you want to delete "${boardTitle}"?\n\nWARNING: ALL POSTS in this board will be PERMANENTLY DELETED.`)) {
            const res = await fetch("/api/board/delete", {
                method: "DELETE",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ id: boardId })
            });
            if (res.ok) {
                fetchBoards();
            } else {
                alert("Failed to delete board.");
            }
        }
    };

    if (session?.user?.role !== "ADMIN") {
        return <div className="p-8 text-white">Access Denied</div>;
    }

    return (
        <div className="min-h-screen p-8 bg-wos-bg">
            <div className="max-w-6xl mx-auto">
                <div className="flex justify-between items-center mb-10">
                    <h1 className="text-3xl font-bold text-sky-400 font-heading">Global Boards Management</h1>
                    <button
                        onClick={() => { resetForm(); setShowModal(true); }}
                        className="bg-violet-600 hover:bg-violet-500 text-white font-bold px-6 py-2 rounded shadow-lg transition-transform hover:scale-105"
                    >
                        + Create Board
                    </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {boards.map(board => (
                        <div key={board.id} className="bg-wos-surface border border-white/5 p-6 rounded-lg relative group hover:border-ice-500/30 transition-colors">
                            <div className="absolute top-4 right-4 z-10">
                                <MenuDropdown
                                    isOpen={activeMenuId === board.id}
                                    onToggle={() => setActiveMenuId(activeMenuId === board.id ? null : board.id)}
                                    onDelete={() => handleDelete(board.id, board.title)}
                                    onEdit={() => openEdit(board)}
                                    viewLink={`/boards/${board.slug}`}
                                />
                            </div>

                            <h3 className="text-xl font-bold text-white mb-1 pr-8">{board.title}</h3>
                            <div className="flex items-center gap-2 mb-4">
                                <span className="text-xs text-slate-500">/{board.slug}</span>
                            </div>
                            <p className="text-slate-400 text-sm mb-4 min-h-[40px] line-clamp-2">{board.description || "No description provided."}</p>

                            <div className="flex justify-end gap-2 opacity-50 group-hover:opacity-100 transition-opacity">
                                <Link href={`/boards/${board.slug}`} className="text-sm text-ice-400 hover:underline">Go to Board →</Link>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Create/Edit Modal */}
                {showModal && (
                    <div className="fixed inset-0 bg-black/70 flex items-center justify-center p-4 z-50 backdrop-blur-sm">
                        <div className="bg-slate-800 p-8 rounded-lg w-full max-w-md border border-slate-700 shadow-2xl">
                            <h2 className="text-2xl font-bold text-white mb-6">{editingId ? "Board Settings" : "Create New Board"}</h2>
                            <form onSubmit={handleCreate} className="space-y-4">
                                <div>
                                    <label className="block text-xs font-bold text-slate-400 mb-1">Title</label>
                                    <input className="w-full bg-slate-900 border border-slate-700 p-2 rounded text-white" value={title} onChange={e => { setTitle(e.target.value); if (!editingId) setSlug(e.target.value.toLowerCase().replace(/\s+/g, '-')); }} required />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-slate-400 mb-1">Slug (URL)</label>
                                    <input className="w-full bg-slate-900 border border-slate-700 p-2 rounded text-slate-400" value={slug} onChange={e => setSlug(e.target.value)} required />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-slate-400 mb-1">Post Categories (comma separated)</label>
                                    <input
                                        className="w-full bg-slate-900 border border-slate-700 p-2 rounded text-white"
                                        placeholder="e.g. Notice, Guide, General"
                                        value={availCats}
                                        onChange={e => setAvailCats(e.target.value)}
                                    />
                                    <p className="text-[10px] text-slate-500 mt-1">Users can select these tags when writing posts.</p>
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-slate-400 mb-1">Description</label>
                                    <textarea className="w-full bg-slate-900 border border-slate-700 p-2 rounded text-white" rows={3} value={desc} onChange={e => setDesc(e.target.value)} />
                                </div>
                                <div className="flex justify-end gap-3 pt-4">
                                    <button type="button" onClick={() => { setShowModal(false); resetForm(); }} className="px-4 py-2 text-slate-400 hover:text-white">Cancel</button>
                                    <button type="submit" className="bg-violet-600 px-6 py-2 rounded text-white font-bold hover:bg-violet-500">{editingId ? "Save Changes" : "Create"}</button>
                                </div>
                            </form>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

// Simple Dropdown Component
function MenuDropdown({ isOpen, onToggle, onDelete, onEdit, viewLink }: { isOpen: boolean, onToggle: () => void, onDelete: () => void, onEdit: () => void, viewLink: string }) {
    return (
        <div className="relative">
            <button
                onClick={(e) => { e.stopPropagation(); onToggle(); }}
                className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-white/10 text-slate-400 hover:text-white transition-colors"
            >
                ⋮
            </button>

            {isOpen && (
                <>
                    <div className="fixed inset-0 z-10" onClick={(e) => { e.stopPropagation(); onToggle(); }} />
                    <div className="absolute right-0 top-full mt-1 w-32 bg-slate-800 border border-slate-700 rounded shadow-xl z-20 py-1 flex flex-col">
                        <Link href={viewLink} className="text-left px-4 py-2 text-sm text-slate-300 hover:bg-slate-700 hover:text-white" onClick={() => onToggle()}>View Board</Link>
                        <button
                            onClick={(e) => { e.stopPropagation(); onToggle(); onEdit(); }}
                            className="text-left px-4 py-2 text-sm text-slate-300 hover:bg-slate-700 hover:text-white"
                        >
                            Settings
                        </button>
                        <hr className="border-slate-700 my-1" />
                        <button
                            onClick={(e) => { e.stopPropagation(); onToggle(); onDelete(); }}
                            className="text-left px-4 py-2 text-sm text-rose-400 hover:bg-rose-500/20 hover:text-rose-300 font-bold"
                        >
                            Delete
                        </button>
                    </div>
                </>
            )}
        </div>
    )
}

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";

interface AdminStats {
    stats: {
        totalUsers: number;
        totalAlliances: number;
        activeUsers24h: number;
    };
    recentAlliances: any[];
}

export default function AdminDashboard() {
    const [data, setData] = useState<AdminStats | null>(null);

    useEffect(() => {
        fetch("/api/admin/stats")
            .then((res) => {
                if (res.ok) return res.json();
                throw new Error("Unauthorized");
            })
            .then(setData)
            .catch(() => window.location.href = "/"); // Redirect if not admin
    }, []);

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure you want to DISBAND this alliance? This cannot be undone.")) return;

        try {
            const res = await fetch("/api/alliance/delete", {
                method: "POST", headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ allianceId: id })
            });

            if (res.ok) {
                alert("Alliance disbanded.");
                // Refresh data
                const stats = await fetch("/api/admin/stats").then(r => r.json());
                setData(stats);
            } else {
                const err = await res.json();
                alert(err.error || "Failed to delete");
            }
        } catch (e) {
            alert("Error deleting alliance");
        }
    };

    if (!data) return <div className="p-8 text-white">Loading Admin Panel...</div>;

    return (
        <div className="min-h-screen bg-slate-900 text-white p-8">
            <div className="max-w-6xl mx-auto">
                <h1 className="text-3xl font-bold font-heading text-sky-400 mb-8">Admin Dashboard</h1>

                {/* Stats Grid */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                    <div className="bg-slate-800 p-6 rounded-lg border border-slate-700">
                        <h3 className="text-slate-400 mb-1">Total Users</h3>
                        <p className="text-3xl font-bold">{data.stats.totalUsers}</p>
                    </div>
                    <div className="bg-slate-800 p-6 rounded-lg border border-slate-700">
                        <h3 className="text-slate-400 mb-1">Active (24h)</h3>
                        <p className="text-3xl font-bold text-emerald-400">{data.stats.activeUsers24h}</p>
                    </div>
                    <div className="bg-slate-800 p-6 rounded-lg border border-slate-700">
                        <h3 className="text-slate-400 mb-1">Alliances</h3>
                        <p className="text-3xl font-bold text-violet-400">{data.stats.totalAlliances}</p>
                    </div>
                </div>

                {/* Quick Links */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                    <Link href="/admin/boards" className="block bg-slate-800 p-6 rounded-lg border border-slate-700 hover:border-sky-500 group transition-colors">
                        <h3 className="text-xl font-bold mb-2 text-sky-400 group-hover:text-sky-300">Manage Boards</h3>
                        <p className="text-slate-400">Create & manage global boards.</p>
                    </Link>
                    <Link href="/admin/users" className="block bg-slate-800 p-6 rounded-lg border border-slate-700 hover:border-emerald-500 group transition-colors">
                        <h3 className="text-xl font-bold mb-2 text-emerald-400 group-hover:text-emerald-300">Manage Users</h3>
                        <p className="text-slate-400">View users, roles, and ban status.</p>
                    </Link>
                    <Link href="/admin/alliances" className="block bg-slate-800 p-6 rounded-lg border border-slate-700 hover:border-violet-500 group transition-colors">
                        <h3 className="text-xl font-bold mb-2 text-violet-400 group-hover:text-violet-300">Manage Alliances</h3>
                        <p className="text-slate-400">Edit, disband, or transfer leadership.</p>
                    </Link>
                </div>

                {/* Removed inline Recent Alliances list in favor of dedicated page */}
            </div>
        </div>
    );
}

"use client";

import { useSession } from "next-auth/react";
import { useEffect, useState } from "react";
import { format } from "date-fns";
import { Loader2, Search, Trash2, Shield, ShieldOff, Ban, CheckCircle, Crown, ShieldAlert, Edit2 } from "lucide-react";
import Image from "next/image";

interface User {
    id: string;
    name: string;
    email: string;
    image: string;
    displayName: string | null;
    serverCode: string | null;
    isActive: boolean;
    isApprovedLeader: boolean;
    role: string;
    lastLogin: string;
    joinedAt: string;
    lastPost: { title: string; createdAt: string } | null;
    lastComment: { content: string; createdAt: string } | null;
    stats: { posts: number; comments: number };
}

interface Alliance {
    id: string;
    tag: string;
    name: string;
}

export default function AdminUsersPage() {
    const { data: session } = useSession();
    const [users, setUsers] = useState<User[]>([]);
    const [alliances, setAlliances] = useState<Alliance[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState("");

    // Inline Editing State
    const [editingUserId, setEditingUserId] = useState<string | null>(null);
    const [editName, setEditName] = useState("");
    const [editServer, setEditServer] = useState("");

    // Alliance Assignment State
    const [assigningUserId, setAssigningUserId] = useState<string | null>(null);

    const handleSaveProfile = async (id: string) => {
        const res = await fetch(`/api/admin/users/${id}`, {
            method: "PATCH",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ displayName: editName, serverCode: editServer })
        });
        if (res.ok) {
            setUsers(users.map(u => u.id === id ? { ...u, displayName: editName, serverCode: editServer } : u));
            setEditingUserId(null);
        } else {
            alert("Failed to update profile");
        }
    };

    const fetchUsersAndAlliances = async () => {
        setLoading(true);
        try {
            const [usersRes, alliancesRes] = await Promise.all([
                fetch("/api/admin/users"),
                fetch("/api/alliance/list")
            ]);

            const usersData = await usersRes.json();
            const alliancesData = await alliancesRes.json();

            if (usersData.users) setUsers(usersData.users);
            if (alliancesData.alliances) setAlliances(alliancesData.alliances);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchUsersAndAlliances();
    }, []);

    const toggleStatus = async (user: User) => {
        const newStatus = !user.isActive;
        const confirmMsg = newStatus ? "Activate this user?" : "Deactivate (Ban) this user?";
        if (!confirm(confirmMsg)) return;

        const res = await fetch(`/api/admin/users/${user.id}`, {
            method: "PATCH",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ isActive: newStatus })
        });

        if (res.ok) {
            setUsers(users.map(u => u.id === user.id ? { ...u, isActive: newStatus } : u));
        } else {
            alert("Failed to update status");
        }
    };

    const togglePermission = async (user: User) => {
        const newStatus = !user.isApprovedLeader;
        const confirmMsg = newStatus ? "Grant R5 (Create Alliance) permission?" : "Revoke R5 permission?";
        if (!confirm(confirmMsg)) return;

        const res = await fetch(`/api/admin/users/${user.id}`, {
            method: "PATCH",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ isApprovedLeader: newStatus })
        });

        if (res.ok) {
            setUsers(users.map(u => u.id === user.id ? { ...u, isApprovedLeader: newStatus } : u));
        } else {
            alert("Failed to update permission");
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm("Are you SURE? This will delete the user and potentially all their content. This cannot be undone.")) return;

        const res = await fetch(`/api/admin/users/${id}`, {
            method: "DELETE"
        });

        if (res.ok) {
            setUsers(users.filter(u => u.id !== id));
        } else {
            alert("Failed to delete");
        }
    };

    const filteredUsers = users.filter(u =>
        u.name?.toLowerCase().includes(search.toLowerCase()) ||
        u.email?.toLowerCase().includes(search.toLowerCase()) ||
        u.displayName?.toLowerCase().includes(search.toLowerCase())
    );

    if (loading) {
        return (
            <div className="flex justify-center items-center py-20">
                <Loader2 className="animate-spin text-ice-500" size={48} />
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-wos-bg p-8">
            <div className="max-w-7xl mx-auto">
                <div className="flex justify-between items-center mb-8">
                    <h1 className="text-3xl font-bold font-heading text-white">User Management</h1>
                    <div className="relative">
                        <input
                            type="text"
                            placeholder="Search users..."
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            className="bg-slate-900 border border-slate-700 rounded-lg pl-10 pr-4 py-2 text-white focus:border-ice-500 outline-none w-64"
                        />
                        <Search className="absolute left-3 top-2.5 text-slate-500" size={18} />
                    </div>
                </div>

                <div className="bg-wos-surface border border-slate-700 rounded-xl overflow-hidden shadow-xl">
                    <div className="overflow-x-auto">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-slate-900/50 border-b border-slate-700 text-slate-400 text-xs uppercase tracking-wider">
                                    <th className="p-4">User</th>
                                    <th className="p-4">Status</th>
                                    <th className="p-4">Activity</th>
                                    <th className="p-4">Last Interaction</th>
                                    <th className="p-4 text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-800">
                                {filteredUsers.map(user => (
                                    <tr key={user.id} className="hover:bg-slate-800/30 transition-colors">
                                        <td className="p-4">
                                            <div className="flex items-center gap-3">
                                                <div className="w-10 h-10 rounded-full bg-slate-700 overflow-hidden relative border border-slate-600">
                                                    {user.image ? (
                                                        <Image src={user.image} alt={user.name} fill className="object-cover" />
                                                    ) : (
                                                        <div className="flex items-center justify-center h-full w-full text-white font-bold">{user.name?.[0]}</div>
                                                    )}
                                                </div>
                                                <div>
                                                    <div className="font-bold text-white text-sm flex items-center gap-2 group cursor-pointer" onClick={() => {
                                                        setEditingUserId(user.id);
                                                        setEditName(user.displayName || user.name || "");
                                                        setEditServer(user.serverCode || "");
                                                    }}>

                                                        {editingUserId === user.id ? (
                                                            <div className="flex items-center gap-2 bg-slate-900 border border-ice-500 rounded px-2 py-1 relative z-10 w-full" onClick={e => e.stopPropagation()}>
                                                                <input
                                                                    autoFocus
                                                                    className="bg-transparent outline-none text-white text-sm w-32"
                                                                    value={editName}
                                                                    onChange={e => setEditName(e.target.value)}
                                                                    onKeyDown={e => e.key === "Enter" && handleSaveProfile(user.id)}
                                                                    placeholder="Name"
                                                                />
                                                                <input
                                                                    className="bg-transparent outline-none text-fire-400 text-xs w-16 px-1 border-l border-slate-700 ml-1"
                                                                    value={editServer}
                                                                    onChange={e => setEditServer(e.target.value)}
                                                                    onKeyDown={e => e.key === "Enter" && handleSaveProfile(user.id)}
                                                                    placeholder="#Server"
                                                                />
                                                                <button onClick={() => handleSaveProfile(user.id)} className="text-green-400 hover:text-green-300 ml-1"><CheckCircle size={14} /></button>
                                                                <button onClick={() => setEditingUserId(null)} className="text-red-400 hover:text-red-300"><Ban size={14} /></button>
                                                            </div>
                                                        ) : (
                                                            <>
                                                                <span>{user.displayName || user.name}</span>
                                                                <Edit2 size={12} className="opacity-0 group-hover:opacity-100 text-slate-500 hover:text-ice-400 transition-all" />
                                                            </>
                                                        )}

                                                        {user.role === "ADMIN" && editingUserId !== user.id && <span className="bg-violet-500/20 text-violet-400 text-[10px] px-1.5 rounded border border-violet-500/30">ADMIN</span>}
                                                    </div>
                                                    <div className="text-xs text-slate-500">{user.email}</div>
                                                    {user.serverCode && editingUserId !== user.id && <div className="text-[10px] text-fire-400 bg-fire-500/10 inline-block px-1 rounded mt-0.5">{user.serverCode}</div>}
                                                </div>
                                            </div>
                                        </td>
                                        <td className="p-4">
                                            {user.isActive ? (
                                                <span className="flex items-center gap-1.5 text-xs font-bold text-green-400 bg-green-400/10 px-2 py-1 rounded-full w-fit">
                                                    <CheckCircle size={12} /> Active
                                                </span>
                                            ) : (
                                                <span className="flex items-center gap-1.5 text-xs font-bold text-red-400 bg-red-400/10 px-2 py-1 rounded-full w-fit">
                                                    <Ban size={12} /> Banned
                                                </span>
                                            )}
                                        </td>
                                        <td className="p-4">
                                            <div className="text-xs text-slate-400">
                                                <div>Posts: <span className="text-white font-bold">{user.stats.posts}</span></div>
                                                <div>Comments: <span className="text-white font-bold">{user.stats.comments}</span></div>
                                                <div className="mt-1 text-slate-500">
                                                    Active: {format(new Date(user.lastLogin), "MMM d, h:mm a")}
                                                </div>
                                            </div>
                                        </td>
                                        <td className="p-4 max-w-xs">
                                            <div className="space-y-2">
                                                {user.lastPost ? (
                                                    <div className="text-xs">
                                                        <span className="text-ice-400 font-bold block mb-0.5">Post</span>
                                                        <p className="text-slate-300 truncate" title={user.lastPost.title}>{user.lastPost.title}</p>
                                                        <span className="text-[10px] text-slate-500">{format(new Date(user.lastPost.createdAt), "MMM d")}</span>
                                                    </div>
                                                ) : <div className="text-xs text-slate-600 italic">No posts</div>}

                                                {user.lastComment ? (
                                                    <div className="text-xs border-t border-slate-800 pt-1">
                                                        <span className="text-emerald-400 font-bold block mb-0.5">Comment</span>
                                                        <p className="text-slate-300 truncate" title={user.lastComment.content}>{user.lastComment.content}</p>
                                                        <span className="text-[10px] text-slate-500">{format(new Date(user.lastComment.createdAt), "MMM d")}</span>
                                                    </div>
                                                ) : null}
                                            </div>
                                        </td>
                                        <td className="p-4 text-right">
                                            <div className="flex flex-col items-end gap-2">
                                                <div className="flex justify-end gap-2">
                                                    {user.role !== "ADMIN" && (
                                                        <>
                                                            <button
                                                                onClick={() => setAssigningUserId(assigningUserId === user.id ? null : user.id)}
                                                                className={`p-2 rounded hover:bg-slate-700 transition-colors ${assigningUserId === user.id ? "text-sky-400" : "text-slate-600 hover:text-sky-400"}`}
                                                                title="Assign to Alliance"
                                                            >
                                                                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2" /><circle cx="9" cy="7" r="4" /><line x1="19" x2="19" y1="8" y2="14" /><line x1="22" x2="16" y1="11" y2="11" /></svg>
                                                            </button>
                                                            <button
                                                                onClick={async () => {
                                                                    if (confirm(`Grant GLOBAL ADMIN to ${user.displayName || user.name}?`)) {
                                                                        await fetch(`/api/admin/users/${user.id}`, {
                                                                            method: "PATCH",
                                                                            headers: { "Content-Type": "application/json" },
                                                                            body: JSON.stringify({ globalRole: "ADMIN" })
                                                                        });
                                                                        fetchUsersAndAlliances();
                                                                    }
                                                                }}
                                                                className="p-2 rounded hover:bg-slate-700 text-slate-600 hover:text-violet-400 transition-colors"
                                                                title="Grant Global Admin"
                                                            >
                                                                <ShieldAlert size={18} />
                                                            </button>
                                                            <button
                                                                onClick={() => togglePermission(user)}
                                                                className={`p-2 rounded hover:bg-slate-700 transition-colors ${user.isApprovedLeader ? "text-amber-400 hover:text-amber-300" : "text-slate-600 hover:text-amber-400"}`}
                                                                title={user.isApprovedLeader ? "Revoke Creator Permission" : "Grant Creator Permission"}
                                                            >
                                                                <Crown size={18} />
                                                            </button>
                                                            <button
                                                                onClick={() => toggleStatus(user)}
                                                                className={`p-2 rounded hover:bg-slate-700 transition-colors ${user.isActive ? "text-slate-400 hover:text-red-400" : "text-green-500 hover:text-green-400"}`}
                                                                title={user.isActive ? "Deactivate User" : "Activate User"}
                                                            >
                                                                {user.isActive ? <ShieldOff size={18} /> : <Shield size={18} />}
                                                            </button>
                                                            <button
                                                                onClick={() => handleDelete(user.id)}
                                                                className="p-2 rounded hover:bg-slate-700 text-slate-400 hover:text-red-500 transition-colors"
                                                                title="Delete User"
                                                            >
                                                                <Trash2 size={18} />
                                                            </button>
                                                        </>
                                                    )}
                                                </div>

                                                {assigningUserId === user.id && (
                                                    <div className="bg-slate-900 border border-slate-700 p-2 rounded flex items-center gap-2 mt-2 absolute right-8 z-20 shadow-xl" onClick={e => e.stopPropagation()}>
                                                        <select
                                                            className="bg-slate-800 text-xs text-white border border-slate-600 rounded p-1 outline-none focus:border-sky-500"
                                                            onChange={async (e) => {
                                                                if (!e.target.value) return;
                                                                if (confirm(`Force assign ${user.displayName || user.name} to this Alliance?`)) {
                                                                    const res = await fetch(`/api/admin/users/${user.id}`, {
                                                                        method: "PATCH",
                                                                        headers: { "Content-Type": "application/json" },
                                                                        body: JSON.stringify({ forceAllianceId: e.target.value })
                                                                    });
                                                                    if (res.ok) {
                                                                        setAssigningUserId(null);
                                                                        fetchUsersAndAlliances();
                                                                    } else {
                                                                        alert("Assignment failed!");
                                                                    }
                                                                }
                                                            }}
                                                        >
                                                            <option value="">Select Alliance...</option>
                                                            {alliances.map(a => (
                                                                <option key={a.id} value={a.id}>[{a.tag}] {a.name}</option>
                                                            ))}
                                                        </select>
                                                        <button onClick={() => setAssigningUserId(null)} className="text-slate-500 hover:text-red-400"><Trash2 size={14} /></button>
                                                    </div>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                                {filteredUsers.length === 0 && (
                                    <tr>
                                        <td colSpan={5} className="p-8 text-center text-slate-500">
                                            No users found.
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
        </div>
    );
}

﻿"use client";

import { Bell, BellOff, CalendarDays, Crown, FileText, Hash, Home, Menu, Pencil, Repeat, Settings, Shield, Trash2, Users, X } from "lucide-react";
import { useSession } from "next-auth/react";
import { useEffect, useState, useRef } from "react";
import { useParams } from "next/navigation";
import Link from "next/link";
import PostList from "@/components/PostList";
import MinistryScheduler from "@/components/Ministry/MinistryScheduler";
import toast, { Toaster } from 'react-hot-toast';

export interface AllianceMember {
    id: string;
    role: string;
    user: { id: string; name: string; displayName?: string; image?: string };
}

export interface AllianceChannel {
    id: string;
    name: string;
    minRole: string;
    minReadRole: string;
}

