                        <span className="text-ice-500">Ministry</span> Schedule
                    </h1>
                    <p className="text-slate-400">
                        Maximize your state's power by reserving the right Minister for the right day.
                        Requests must be approved by the Presidency.
                    </p>
                </header>

                <MinistryScheduler allianceId={allianceId} />
            </div>
        </div>
    );
}

"use client";

import { useState, useRef } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import RichEditor from "@/components/RichEditor";
import { useSession } from "next-auth/react";

export default function AllianceWritePage() {
    const { id, boardId } = useParams();
    const router = useRouter();
    const { data: session } = useSession();

    const [title, setTitle] = useState("");
    const [category, setCategory] = useState("General");
    const [content, setContent] = useState("");
    const [tags, setTags] = useState("");
    const [isSubmitting, setIsSubmitting] = useState(false);

    // File Upload State
    const [isUploading, setIsUploading] = useState(false);
    const [totalBytes, setTotalBytes] = useState(0);
    const MAX_FILE_SIZE = 3 * 1024 * 1024; // 3MB
    const MAX_TOTAL_SIZE = 15 * 1024 * 1024; // 15MB
    const fileInputRef = useRef<HTMLInputElement>(null);

    const formatBytes = (bytes: number) => {
        if (bytes === 0) return '0 Bytes';
        const k = 1024;
        const sizes = ['Bytes', 'KB', 'MB', 'GB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    };

    const handleUpload = async (e: React.ChangeEvent<HTMLInputElement> | { target: { files: FileList | File[] } }) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (file.size > MAX_FILE_SIZE) {
            alert(`File too large. Max 3MB per image.`);
            return;
        }

        if (totalBytes + file.size > MAX_TOTAL_SIZE) {
            alert(`Total size limit (15MB) exceeded.`);
            return;
        }

        setIsUploading(true);
        const formData = new FormData();
        formData.append("file", file);

        try {
            const res = await fetch("/api/upload", {
                method: "POST",
                body: formData,
            });

            if (!res.ok) throw new Error("Upload failed");

            const data = await res.json();
            const imgTag = `<img src="${data.url}" alt="${file.name}" class="rounded-lg my-4 max-h-[500px]" />`;
            setContent(prev => prev + imgTag);
            setTotalBytes(prev => prev + file.size);

        } catch (error) {
            console.error(error);
            alert("Upload failed.");
        } finally {
            setIsUploading(false);
            if (fileInputRef.current) fileInputRef.current.value = "";
        }
    };

    // Category mocked or fixed for now
    const categories = ["General", "Announcement", "Strategy", "Question"];

    const handleSubmit = async () => {
        if (!title.trim()) return alert("Please enter a title.");
        if (!content || content === '<p></p>') return alert("Please enter content.");
        if (!boardId) return alert("System Error: Board ID is missing. Please refresh.");

        setIsSubmitting(true);

        const res = await fetch("/api/post/create", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                title,
                content,
                boardId,
                allianceId: id,
                category,
                tags: tags.split(",").map(t => t.trim()).filter(Boolean)
            })
        });

        if (res.ok) {
            router.push(`/alliances/${id}`);
        } else {
            alert("Failed to create post.");
        }
        setIsSubmitting(false);
    };

    return (
        <div className="min-h-screen p-4 md:p-8 flex justify-center">
            <div className="w-full max-w-5xl bg-wos-surface border border-white/5 rounded-lg shadow-2xl overflow-hidden flex flex-col">

                {/* Header Section */}
                <div className="p-6 border-b border-white/5 bg-slate-900/50">
                    <h1 className="text-2xl font-bold text-white font-heading mb-6 tracking-wide">
                        Alliance Board <span className="text-slate-500 text-lg font-normal">/ Write Post</span>
                    </h1>

                    {/* Title Input */}
                    <input
                        type="text"
                        placeholder="Title"
                        className="w-full bg-slate-800/50 border border-slate-700 text-white p-4 rounded text-lg focus:border-ice-500 focus:ring-1 focus:ring-ice-500 transition-all outline-none placeholder:text-slate-600 mb-4"
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                    />

                    {/* Category Tabs */}
                    <div className="flex flex-wrap items-center gap-2">
                        <span className="text-ice-400 text-sm font-bold mr-2">* Category</span>
                        {categories.map((cat) => (
                            <button
                                key={cat}
                                onClick={() => setCategory(cat)}
                                className={`px-4 py-1.5 rounded-full text-sm transition-all border ${category === cat
                                    ? "bg-ice-600/20 border-ice-500 text-ice-400 shadow-[0_0_10px_rgba(56,189,248,0.2)]"
                                    : "bg-slate-800/50 border-transparent text-slate-400 hover:text-white hover:bg-slate-700"
                                    }`}
                            >
                                {cat}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Editor Area */}
                <div className="flex-1 p-2">
                    <RichEditor
                        content={content}
                        onChange={(html) => setContent(html)}
                        placeholder="Share your thoughts..."
                        onImageUpload={async (file) => {
                            // Adapter to return URL
                            if (file.size > MAX_FILE_SIZE) { alert('Too large'); return null; }
                            const formData = new FormData();
                            formData.append("file", file);
                            try {
                                const res = await fetch("/api/upload", { method: "POST", body: formData });
                                if (!res.ok) throw new Error("Upload failed");
                                const data = await res.json();
                                setTotalBytes(prev => prev + file.size);
                                return data.url;
                            } catch (e) { return null; }
                        }}
                    />
                </div>

                {/* Footer Section */}
                <div className="p-6 border-t border-white/5 bg-slate-900/50 space-y-4">
                    {/* Simplified Upload stub */}

                    {/* Tags Input */}
                    <input
                        type="text"
                        placeholder="Tags: Separate with comma (,)"
                        className="w-full bg-slate-800/50 border border-slate-700 text-sm text-white p-3 rounded focus:border-ice-500 focus:outline-none placeholder:text-slate-600"
                        value={tags}
                        onChange={(e) => setTags(e.target.value)}
                    />

                    {/* Action Buttons */}
                    <div className="flex justify-end gap-3 pt-2">
                        <Link href={`/alliances/${id}`} className="px-6 py-2.5 rounded border border-slate-600 text-slate-300 hover:bg-slate-800 transition-colors font-medium">
                            Cancel
                        </Link>
                        <button
                            onClick={handleSubmit}
                            disabled={isSubmitting}
                            className="px-8 py-2.5 rounded bg-ice-600 hover:bg-ice-500 text-white font-bold shadow-[0_4px_14px_0_rgba(2,132,199,0.39)] transition-all flex items-center gap-2 hover:scale-105 disabled:opacity-50 disabled:hover:scale-100"
                        >
                            {isSubmitting ? "Registering..." : "Register"}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import { Menu, X } from "lucide-react";
import { useSession } from "next-auth/react";
import { useEffect, useState, useRef } from "react";
import { useParams } from "next/navigation";
import BoardView from "@/components/BoardView";
import MinistryScheduler from "@/components/Ministry/MinistryScheduler";

export interface AllianceMember {
    id: string;
    role: string;
    user: { id: string; name: string; displayName?: string; image?: string };
}

export interface AllianceChannel {
    id: string;
    name: string;
    minRole: string;
    minReadRole: string;
}

export interface AllianceBoard {
    id: string;
    title: string;
    slug: string;
    minRole: string;
    availableCategories: string[];
}

export interface AlliancePost {
    id: string;
    title: string;
    content: string;
    isPinned: boolean;
    createdAt: string;
    category: string | null;
    author: { id: string; name: string; displayName: string | null; serverCode: string | null; image?: string };
    _count?: { comments: number; reactions?: number };
}

interface AllianceDetail {
    id: string;
    name: string;
    description: string;
    isMember: boolean;
    role: string | null;
    logo?: string;
    banner?: string;
    members?: AllianceMember[];
    channels?: AllianceChannel[];
    boards?: AllianceBoard[];
    enableConstructionRes?: boolean;
    enableTrainingRes?: boolean;
    autoSubscribeEvents?: boolean; // Current user's setting
}

interface Message {
    id: string;
    content: string;
    createdAt: string;
    sender: {
        id: string;
        displayName: string;
        image: string;
    };
}

const BoardSidebarItem = ({ board, activeView, setActiveView, canManage, onOpenSettings }: {
    board: AllianceBoard, activeView: string, setActiveView: (v: string) => void, canManage: boolean, onOpenSettings: (board: AllianceBoard) => void
}) => {
    const [isHovered, setIsHovered] = useState(false);

    return (
        <div
            className={`relative group/board w-full flex items-center gap-1 rounded-md transition-colors px-3 py-1.5 ${activeView === board.id ? "bg-slate-700 text-white font-medium" : "text-slate-400 hover:bg-slate-800 hover:text-slate-200"}`}
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
        >
            <div
                className="flex-1 flex items-center gap-2 overflow-hidden cursor-pointer min-w-0"
                onClick={() => setActiveView(board.id)}
            >
                <span className="text-slate-600 shrink-0">📄</span>
                <span className="truncate text-sm">{board.title}</span>
                {board.minRole && board.minRole !== "R1" && <span className="text-[10px] bg-slate-700 px-1 rounded text-slate-500 border border-slate-600 shrink-0">{board.minRole}+</span>}
            </div>

            {/* Gear Icon Trigger */}
            {canManage && (isHovered) && (
                <button
                    onClick={(e) => {
                        e.stopPropagation();
                        onOpenSettings(board);
                    }}
                    className="p-1 rounded cursor-pointer transition-colors shrink-0 text-slate-500 hover:text-ice-400 hover:bg-slate-700"
                >
                    ⚙️
                </button>
            )}
        </div>
    );
};

