        }

        const alliances = await prisma.alliance.findMany({
            orderBy: orderBy,
            include: {
                createdBy: { select: { displayName: true } },
                _count: { select: { members: true } }
            }
        });

        return NextResponse.json({ alliances });
    } catch (error) {
        return NextResponse.json({ error: "Server error" }, { status: 500 });
    }
