import { NextResponse } from "next/server";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { RRule } from "rrule";

export const dynamic = 'force-dynamic';

export async function GET(req: Request) {
    try {
        const session = await getServerSession(authOptions);

        if (!session?.user?.id) {
            return NextResponse.json({ events: [] });
        }

        const userId = session.user.id;

        // 1. Get User's Alliances
        const user = await prisma.user.findUnique({
            where: { id: userId },
            select: {
                memberships: {
                    select: { allianceId: true, alliance: { select: { name: true } } }
                }
            }
        });

        const allianceIds = user?.memberships.map(m => m.allianceId) || [];

        // 2. Fetch Alliance Events
        const events = await prisma.event.findMany({
            where: {
                allianceId: { in: allianceIds }
            },
            include: {
                alliance: {
                    select: { name: true }
                }
            },
            orderBy: { startTime: 'asc' }
        });

        // 3. Fetch Construction Reservations
        const construction = await prisma.constructionReservation.findMany({
            where: { userId },
            include: { alliance: { select: { name: true } } },
            orderBy: { startTime: 'asc' }
        });

        // 4. Fetch Training Reservations
        const training = await prisma.trainingReservation.findMany({
            where: { userId },
            include: { alliance: { select: { name: true } } },
            orderBy: { startTime: 'asc' }
        });

        // 5. Fetch Ministry Reservations
        const ministry = await prisma.ministryReservation.findMany({
            where: { userId },
            orderBy: { startTime: 'asc' }
        });

        const now = new Date();
        const nextYear = new Date();
        nextYear.setFullYear(now.getFullYear() + 1);

        // 6. Process Recurring Events
        const expandedEvents: any[] = [];

        events.forEach(e => {
            if (e.recurrenceRule) {
                try {
                    // Create RRule instance
                    // Note: RRule.parseString handles standard parsing. 
                    // We manually set dtstart to the event's start time relative to UTC/Local mixing issue?
                    // RRule works with local dates by default if no timezone specified.
                    // Assuming e.startTime is a Date object from Prisma

                    const options = RRule.parseString(e.recurrenceRule);
                    options.dtstart = e.startTime;

                    const rule = new RRule(options);
                    const dates = rule.between(now, nextYear, true); // include dates from now to next year

                    dates.forEach(date => {
                        // Calculate end time
                        let endTime = null;
                        if (e.endTime) {
                            const duration = e.endTime.getTime() - e.startTime.getTime();
                            endTime = new Date(date.getTime() + duration);
                        }

                        expandedEvents.push({
                            id: `${e.id}-${date.getTime()}`, // Unique compound ID
                            title: e.title,
                            startTime: date,
                            endTime: endTime,
                            description: e.description,
                            allianceId: e.allianceId,
                            allianceName: e.alliance?.name,
                            type: 'EVENT'
                        });
                    });

                } catch (err) {
                    console.error(`Recurrence Error for ${e.id}:`, err);
                    // Fallback to original
                    expandedEvents.push({
                        id: e.id,
                        title: e.title,
                        startTime: e.startTime,
                        endTime: e.endTime,
                        description: e.description,
                        allianceId: e.allianceId,
                        allianceName: e.alliance?.name,
                        type: 'EVENT'
                    });
                }
            } else {
                // Single event
                expandedEvents.push({
                    id: e.id,
                    title: e.title,
                    startTime: e.startTime,
                    endTime: e.endTime,
                    description: e.description,
                    allianceId: e.allianceId,
                    allianceName: e.alliance?.name,
                    type: 'EVENT'
                });
            }
        });

        // 7. Merge & Normalize
        const calendarEvents = [
            ...expandedEvents,
            ...construction.map(c => ({
                id: c.id,
                title: `Construction (${c.alliance.name})`,
                startTime: c.startTime,
                endTime: c.endTime,
                description: c.note || "Construction Reservation",
                allianceId: c.allianceId,
                allianceName: c.alliance.name,
                type: 'CONSTRUCTION'
            })),
            ...training.map(t => ({
                id: t.id,
                title: `Training (${t.alliance.name})`,
                startTime: t.startTime,
                endTime: t.endTime,
                description: t.note || "Training Reservation",
                allianceId: t.allianceId,
                allianceName: t.alliance.name,
                type: 'TRAINING'
            })),
            ...ministry.map(m => ({
                id: m.id,
                title: `Ministry: ${m.position}`,
                startTime: m.startTime,
                endTime: m.endTime,
                description: m.adminNote || "Ministry Reservation",
                allianceId: null,
                type: 'MINISTRY'
            }))
        ];

        return NextResponse.json({ events: calendarEvents });

    } catch (error) {
        console.error("Calendar API Error:", error);
        return NextResponse.json({ error: "Failed to fetch calendar" }, { status: 500 });
    }
}

import { prisma } from "@/lib/prisma";
import { NextResponse } from "next/server";
import { sendPushNotification } from "@/lib/push";

export async function GET(req: Request) {
    // Basic securing of the cron endpoint using a shared secret in env
    const authHeader = req.headers.get("authorization");
    const cronSecret = process.env.CRON_SECRET || "development-cron-secret";

    // Allow if in dev or if the Authorization header matches Bearer {CRON_SECRET}
    if (process.env.NODE_ENV === "production" && authHeader !== `Bearer ${cronSecret}`) {
        return new NextResponse("Unauthorized", { status: 401 });
    }

    try {
        const now = new Date();
        const fifteenMinutesFromNow = new Date(now.getTime() + 15 * 60 * 1000);

        // Find events starting in the next 15 minutes that haven't sent a reminder
        const upcomingEvents = await prisma.event.findMany({
            where: {
                startTime: {
                    gte: now,
                    lte: fifteenMinutesFromNow
                },
                reminderSent: false
            },
            include: {
                alliance: {
                    select: { name: true }
                },
                subscriptions: {
                    select: { userId: true }
                }
            }
        });

        console.log(`[CRON] Found ${upcomingEvents.length} events needing reminders.`);

        const notificationsSent: string[] = [];

        for (const event of upcomingEvents) {
            const userIds = event.subscriptions.map((sub: any) => sub.userId);

            if (userIds.length > 0) {
                // Send push notification to all subscribed users
                const pushPromises = userIds.map((userId: string) => {
                    return sendPushNotification(userId, {
                        title: "Alliance Event Starting Soon! ⚔️",
                        message: `${event.title} in ${event.alliance.name} starts in less than 15 minutes!`,
                        url: `/alliances/${event.allianceId}`
                    });
                });

                await Promise.all(pushPromises);
                notificationsSent.push(`Event: ${event.title}, Sent: ${userIds.length}`);
            }

            // Mark as sent
            await prisma.event.update({
                where: { id: event.id },
                data: { reminderSent: true }
            });
        }

        return NextResponse.json({
            success: true,
            eventsProcessed: upcomingEvents.length,
            notificationsSent
        });

    } catch (error) {
        console.error("[CRON ERROR] Event Reminders:", error);
        return new NextResponse("Internal Server Error", { status: 500 });
    }
}

