"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useState, useEffect } from "react";
import toast, { Toaster } from "react-hot-toast";

export default function OnboardingPage() {
    const { data: session, update } = useSession();
    const router = useRouter();

    // Form
    const [serverCode, setServerCode] = useState("");
    const [displayName, setDisplayName] = useState("");
    const [playerId, setPlayerId] = useState("");
    const [gameAvatar, setGameAvatar] = useState("");

    const [loading, setLoading] = useState(false);
    const [fetchingWos, setFetchingWos] = useState(false);

    useEffect(() => {
        if (session) {
            // @ts-ignore
            if (session.user?.serverCode) setServerCode(session.user.serverCode);
            // @ts-ignore
            if (session.user?.displayName) setDisplayName(session.user.displayName);
        }
    }, [session]);

    const handleFetchWosProfile = async () => {
        if (!playerId.trim()) {
            toast.error("Please enter a valid Player ID first.");
            return;
        }

        setFetchingWos(true);
        const tId = toast.loading("Checking Whiteout Survival servers...");

        try {
            const res = await fetch(`/api/player/${playerId}`);
            const data = await res.json();

            if (!res.ok) {
                toast.error(data.error || "Failed to find player data.", { id: tId });
                return;
            }

            if (data.player) {
                // Century Games API returns nickname and avatar_image
                if (data.player.nickname) setDisplayName(data.player.nickname);
                if (data.player.avatar_image) setGameAvatar(data.player.avatar_image);
                // `kid` often correlates to the Kingdom/Server ID
                if (data.player.kid) setServerCode(`#${data.player.kid}`);

                toast.success(`Found Profile: ${data.player.nickname}`, { id: tId });
            }
        } catch (error) {
            console.error(error);
            toast.error("An error occurred fetching game data.", { id: tId });
        } finally {
            setFetchingWos(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        const payload: any = { serverCode, displayName };
        if (gameAvatar) payload.image = gameAvatar;

        const res = await fetch("/api/user/update-profile", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(payload)
        });

        if (res.ok) {
            await update(); // Force session update
            router.push("/");
        } else {
            toast.error("Failed to update profile");
        }
        setLoading(false);
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-slate-900 text-white p-4">
            <Toaster position="top-center" />
            <div className="bg-slate-800 p-8 rounded-lg shadow-2xl max-w-md w-full border border-slate-700">
                <div className="flex flex-col items-center mb-6">
                    {gameAvatar ? (
                        <img src={gameAvatar} alt="Game Avatar" className="w-20 h-20 rounded-xl shadow-lg border-2 border-sky-500 mb-4" />
                    ) : (
                        <div className="w-20 h-20 rounded-xl bg-slate-700 border-2 border-slate-600 mb-4 flex items-center justify-center text-3xl">
                            ❄️
                        </div>
                    )}
                    <h1 className="text-2xl font-bold text-center text-sky-400">Welcome to WOS Community</h1>
                    <p className="text-slate-400 text-center text-sm mt-1">Please complete your profile or fetch it automatically.</p>
                </div>

                {/* Auto-Fetch Section */}
                <div className="bg-slate-900/50 p-4 rounded-lg border border-slate-700/50 mb-6">
                    <label className="block text-xs font-bold text-sky-400 uppercase mb-2 flex items-center gap-2">
                        <span>⚡</span> Auto-Fill with WOS Profile
                    </label>
                    <div className="flex gap-2">
                        <input
                            className="flex-1 bg-slate-900 border border-slate-600 p-2.5 rounded text-white focus:border-sky-500 outline-none transition-colors text-sm placeholder:text-slate-500"
                            placeholder="Player ID (e.g. 130198083)"
                            value={playerId}
                            onChange={(e) => setPlayerId(e.target.value)}
                        />
                        <button
                            type="button"
                            onClick={handleFetchWosProfile}
                            disabled={fetchingWos || !playerId.trim()}
                            className="bg-slate-700 hover:bg-slate-600 disabled:opacity-50 text-white font-bold px-4 py-2.5 rounded text-sm transition-colors whitespace-nowrap"
                        >
                            {fetchingWos ? "Loading..." : "Fetch"}
                        </button>
                    </div>
                    <p className="text-[10px] text-slate-500 mt-2 leading-relaxed">
                        Find your Player ID (FID) in your in-game Chief Profile (top-left avatar). We will securely fetch your Name, Server, and Avatar.
                    </p>
                </div>

                <div className="relative flex items-center py-2 mb-6">
                    <div className="flex-grow border-t border-slate-700"></div>
                    <span className="flex-shrink-0 mx-4 text-slate-500 text-xs font-bold uppercase">Or enter manually</span>
                    <div className="flex-grow border-t border-slate-700"></div>
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div>
                        <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Server Code</label>
                        <input
                            className="w-full bg-slate-900 border border-slate-600 p-3 rounded text-white focus:border-sky-500 outline-none transition-colors"
                            placeholder="#1234"
                            value={serverCode}
                            onChange={(e) => setServerCode(e.target.value)}
                            required
                        />
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Display Name</label>
                        <input
                            className="w-full bg-slate-900 border border-slate-600 p-3 rounded text-white focus:border-sky-500 outline-none transition-colors"
                            placeholder="Your In-Game Name"
                            value={displayName}
                            onChange={(e) => setDisplayName(e.target.value)}
                            required
                        />
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full bg-sky-600 hover:bg-sky-500 disabled:opacity-50 text-white font-bold py-3 rounded mt-4 transition-all shadow-lg shadow-sky-900/20"
                    >
                        {loading ? "Saving Profile..." : "Complete Profile"}
                    </button>
                </form>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import { useSession } from "next-auth/react";
import Link from "next/link";
import { safeDecodeURIComponent } from "@/lib/utils";
import PostList from "@/components/PostList";

interface Post {
    id: string;
    title: string;
    content: string;
    category: string | null;
    author: { displayName: string | null; serverCode: string | null };
    createdAt: string;
    _count: { comments: number };
}

export default function BoardDetail() {
    const { slug } = useParams();
    const { data: session } = useSession();
    const [posts, setPosts] = useState<Post[]>([]);
    const [pinnedPosts, setPinnedPosts] = useState<Post[]>([]);
    const [pinnedType, setPinnedType] = useState<"WEEKLY" | "ALL_TIME">("WEEKLY");
    const [loading, setLoading] = useState(true);
    const [boardTitle, setBoardTitle] = useState("");
    const [canWrite, setCanWrite] = useState(true);
    const [notFound, setNotFound] = useState(false);

    useEffect(() => {
        if (slug) {
            const currentSlug = safeDecodeURIComponent(slug);
            // Decode the slug to show readable text initially (fallback)
            setBoardTitle(currentSlug);

            const fetchBoard = async () => {
                try {
                    const res = await fetch(`/api/post/list?boardSlug=${encodeURIComponent(currentSlug)}`);
                    if (res.status === 404) {
                        setLoading(false);
                        setBoardTitle(""); // or a distinct state
                        setPosts([]); // clear posts
                        return setNotFound(true);
                    }
                    const data = await res.json();

                    if (data.posts) setPosts(data.posts);
                    if (data.pinned) setPinnedPosts(data.pinned);
                    if (data.pinnedType) setPinnedType(data.pinnedType);

                    if (data.board) {
                        setBoardTitle(data.board.title);
                        setCanWrite(data.board.canWrite ?? true);
                    }
                } catch (e) {
                    console.error("Failed to fetch posts or board info");
                } finally {
                    setLoading(false);
                }
            }
            fetchBoard();
        }
    }, [slug]);

    if (notFound) {
        return (
            <div className="min-h-screen flex items-center justify-center flex-col gap-4 text-slate-400">
                <h1 className="text-2xl font-bold text-white">404 - Board Not Found</h1>
                <p>The board you are looking for does not exist.</p>
                <Link href="/boards" className="text-ice-400 hover:underline">Return to Boards</Link>
            </div>
        );
    }

    return (
        <div className="min-h-screen p-4 md:p-8">
            <div className="max-w-6xl mx-auto">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
                    <div>
                        <Link href="/boards" className="text-ice-400 text-sm hover:text-white transition-colors mb-2 inline-block">← Back to Boards</Link>
                        <h1 className="text-4xl font-bold font-heading text-white tracking-tight flex items-center gap-3">
                            <span className="text-ice-500">#</span> {boardTitle}
                        </h1>
                        <p className="text-slate-400 text-sm mt-1">Discuss everything about {boardTitle}</p>
                    </div>
                    {session && canWrite && (
                        <Link
                            href={`/boards/${slug}/write`}
                            className="bg-ice-600 hover:bg-ice-500 text-white px-6 py-2.5 rounded font-bold shadow-[0_0_15px_rgba(14,165,233,0.4)] hover:scale-105 transition-all flex items-center gap-2"
                        >
                            <span>✏️</span> Write Post
                        </Link>
                    )}
                </div>

                {/* Posts List */}
                <PostList
                    posts={posts}
                    pinnedPosts={pinnedPosts}
                    pinnedType={pinnedType}
                    loading={loading}
                    emptyMessage="Be the first to share your survival story."
                    linkPrefix={`/boards/${slug}`} // Explicitly pass the board slug prefix
                />

                {!loading && posts.length === 0 && session && (
                    <div className="text-center mt-4">
                        <Link href={`/boards/${slug}/write`} className="text-ice-400 hover:underline">Write a post now</Link>
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import RichEditor from "@/components/RichEditor";
import { safeDecodeURIComponent } from "@/lib/utils";

export default function WritePage() {
    const { slug } = useParams();
    const router = useRouter();
    const [title, setTitle] = useState("");
    const [category, setCategory] = useState("Info");
    const [content, setContent] = useState("");
    const [tags, setTags] = useState("");
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [boardId, setBoardId] = useState(""); // Need to fetch board ID

    // File Upload State
    const [isUploading, setIsUploading] = useState(false);
    const [totalBytes, setTotalBytes] = useState(0);
    const MAX_FILE_SIZE = 3 * 1024 * 1024; // 3MB
    const MAX_TOTAL_SIZE = 15 * 1024 * 1024; // 15MB
    const fileInputRef = useRef<HTMLInputElement>(null);

    const formatBytes = (bytes: number) => {
        if (bytes === 0) return '0 Bytes';
        const k = 1024;
        const sizes = ['Bytes', 'KB', 'MB', 'GB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    };

    const handleUpload = async (e: React.ChangeEvent<HTMLInputElement> | { target: { files: FileList | File[] } }) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (file.size > MAX_FILE_SIZE) {
            alert(`File too large. Max 3MB per image.`);
            return;
        }

        if (totalBytes + file.size > MAX_TOTAL_SIZE) {
            alert(`Total size limit (15MB) exceeded.`);
            return;
        }

        setIsUploading(true);
        const formData = new FormData();
        formData.append("file", file);

        try {
            const res = await fetch("/api/upload", {
                method: "POST",
                body: formData,
            });

            if (!res.ok) throw new Error("Upload failed");

            const data = await res.json();

            // Insert into editor
            const imgTag = `<img src="${data.url}" alt="${file.name}" class="rounded-lg my-4 max-h-[500px]" />`;
            setContent(prev => prev + imgTag);
            setTotalBytes(prev => prev + file.size);

        } catch (error) {
            console.error(error);
            alert("Upload failed.");
        } finally {
            setIsUploading(false);
            if (fileInputRef.current) fileInputRef.current.value = "";
        }
    };

    // Editor Ref
    // const textareaRef = useRef<HTMLTextAreaElement>(null);

    // const insertText = (text: string) => {
    //    // Removed for WYSIWYG
    // };

    // Mock categories based on reference image replaced by dynamic state
    const [categories, setCategories] = useState<string[]>([]);

    // Fetch Board Metadata
    useEffect(() => {
        if (!slug) return;
        // Use post/list API because it handles retrieving ANY board by slug (Global or Private)
        fetch(`/api/post/list?boardSlug=${encodeURIComponent(safeDecodeURIComponent(slug as string))}&limit=1`)
            .then(res => res.json())
            .then(data => {
                if (data.board) {
                    setBoardId(data.board.id);
                    if (data.board.availableCategories && data.board.availableCategories.length > 0) {
                        setCategories(data.board.availableCategories);
                        setCategory(data.board.availableCategories[0]);
                    } else {
                        setCategories(["General", "Question"]);
                        setCategory("General");
                    }
                } else {
                    // Board not found or access denied
                    alert("Board not found or you don't have permission.");
                    router.push('/boards');
                }
            })
            .catch(err => console.error(err));
    }, [slug]);

    const handleSubmit = async () => {
        if (!title.trim()) return alert("Please enter a title.");
        if (!content || content === '<p></p>') return alert("Please enter content.");
        if (!boardId) return alert("Loading board info... please wait or refresh.");

        setIsSubmitting(true);

        const res = await fetch("/api/post/create", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                title,
                content,
                boardId,
                category,
                tags: tags.split(",").map(t => t.trim()).filter(Boolean)
            })
        });

        if (res.ok) {
            router.push(`/boards/${slug}`);
        } else {
            alert("Failed to create post.");
        }
        setIsSubmitting(false);
    };

    return (
        <div className="min-h-screen p-4 md:p-8 flex justify-center">
            <div className="w-full max-w-5xl bg-wos-surface border border-white/5 rounded-lg shadow-2xl overflow-hidden flex flex-col">

                {/* Header Section */}
                <div className="p-6 border-b border-white/5 bg-slate-900/50">
                    <h1 className="text-2xl font-bold text-white font-heading mb-6 tracking-wide">
                        {safeDecodeURIComponent(slug || "")} <span className="text-slate-500 text-lg font-normal">/ Write Post</span>
                    </h1>

                    {/* Title Input */}
                    <input
                        type="text"
                        placeholder="Title"
                        className="w-full bg-slate-800/50 border border-slate-700 text-white p-4 rounded text-lg focus:border-ice-500 focus:ring-1 focus:ring-ice-500 transition-all outline-none placeholder:text-slate-600 mb-4"
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                    />

                    {/* Category Tabs */}
                    <div className="flex flex-wrap items-center gap-2">
                        <span className="text-ice-400 text-sm font-bold mr-2">* Category</span>
                        {categories.map((cat) => (
                            <button
                                key={cat}
                                onClick={() => setCategory(cat)}
                                className={`px-4 py-1.5 rounded-full text-sm transition-all border ${category === cat
                                    ? "bg-ice-600/20 border-ice-500 text-ice-400 shadow-[0_0_10px_rgba(56,189,248,0.2)]"
                                    : "bg-slate-800/50 border-transparent text-slate-400 hover:text-white hover:bg-slate-700"
                                    }`}
                            >
                                {cat}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Editor Area */}
                <div className="flex-1 p-2">
                    <RichEditor
                        content={content}
                        onChange={(html) => setContent(html)}
                        placeholder="Share your strategy, ask questions, or discuss alliance matters..."
                        onImageUpload={async (file) => {
                            if (file.size > MAX_FILE_SIZE) {
                                alert(`File too large. Max 3MB per image.`);
                                return null;
                            }
                            if (totalBytes + file.size > MAX_TOTAL_SIZE) {
                                alert(`Total size limit (15MB) exceeded.`);
                                return null;
                            }

                            const formData = new FormData();
                            formData.append("file", file);
                            try {
                                const res = await fetch("/api/upload", { method: "POST", body: formData });
                                if (!res.ok) throw new Error("Upload failed");
                                const data = await res.json();
                                setTotalBytes(prev => prev + file.size);
                                return data.url;
                            } catch (e) {
                                console.error(e);
                                alert("Image upload failed");
                                return null;
                            }
                        }}
                    />
                    <div className="text-right text-xs text-slate-500 mt-1 px-4">
                        {/* Char count approximation */}
                        {content.replace(/<[^>]*>/g, '').length} chars
                    </div>
                </div>

                {/* Footer Section */}
                <div className="p-6 border-t border-white/5 bg-slate-900/50 space-y-4">
                    {/* File Upload Stub */}
                    <input
                        type="file"
                        ref={fileInputRef}
                        className="hidden"
                        accept="image/*"
                        onChange={handleUpload}
                    />
                    <div
                        onClick={() => fileInputRef.current?.click()}
                        onDragOver={(e) => e.preventDefault()}
                        onDrop={(e) => {
                            e.preventDefault();
                            const file = e.dataTransfer.files?.[0];
                            if (file) {
                                // Create a synthetic event or call logic directly
                                // For simplicity reuse logic but need to refactor slightly or just pass file
                                const fakeEvent = { target: { files: [file] } } as any;
                                handleUpload(fakeEvent);
                            }
                        }}
                        className="flex items-center gap-4 p-4 bg-slate-800/30 rounded border border-dashed border-slate-700 hover:border-ice-500/50 transition-colors cursor-pointer group"
                    >
                        <div className="bg-ice-600 px-3 py-1.5 rounded text-white text-sm font-bold group-hover:bg-ice-500 transition-colors">
                            {isUploading ? "Uploading..." : "Upload"}
                        </div>
                        <span className="text-slate-500 text-sm group-hover:text-ice-400">
                            Drage images here or click to browse ({formatBytes(totalBytes)} / 15.00 MB)
                        </span>
                    </div>

                    {/* Tags Input */}
                    <input
                        type="text"
                        placeholder="Tags: Separate with comma (,)"
                        className="w-full bg-slate-800/50 border border-slate-700 text-sm text-white p-3 rounded focus:border-ice-500 focus:outline-none placeholder:text-slate-600"
                        value={tags}
                        onChange={(e) => setTags(e.target.value)}
                    />

                    {/* Action Buttons */}
                    <div className="flex justify-end gap-3 pt-2">
                        <Link href={`/boards/${slug}`} className="px-6 py-2.5 rounded border border-slate-600 text-slate-300 hover:bg-slate-800 transition-colors font-medium">
                            Cancel
                        </Link>
                        <button
                            onClick={handleSubmit}
                            disabled={isSubmitting}
                            className="px-8 py-2.5 rounded bg-ice-600 hover:bg-ice-500 text-white font-bold shadow-[0_4px_14px_0_rgba(2,132,199,0.39)] transition-all flex items-center gap-2 hover:scale-105 disabled:opacity-50 disabled:hover:scale-100"
                        >
                            {isSubmitting ? "Registering..." : "Register"}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useSession } from "next-auth/react";
import { useEffect, useState } from "react";
import CalendarView from "@/components/Calendar/CalendarView";

interface Event {
    id: string;
    title: string;
    startTime: string;
    description: string | null;
}

export default function CalendarPage() {
    const { data: session } = useSession();
    const [events, setEvents] = useState<Event[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetch("/api/calendar/my-schedule")
            .then(res => res.json())
