"use client";

import { useSession } from "next-auth/react";
import { useEffect, useState } from "react";

interface MessageData {
    id: string;
    content: string;
    createdAt: string;
    senderId: string;
    sender?: { displayName: string | null };
    receiver?: { displayName: string | null };
}

interface BlockedUserData {
    id: string;
    displayName: string | null;
    serverCode: string | null;
}

interface SelectableUser {
    id: string;
    displayName: string | null;
}

export default function MessagesPage() {
    const { data: session } = useSession();
    const [messages, setMessages] = useState<MessageData[]>([]);
    const [blockedUsers, setBlockedUsers] = useState<BlockedUserData[]>([]);
    const [activeTab, setActiveTab] = useState("inbox");
    const [loading, setLoading] = useState(false);

    // Compose State
    const [servers, setServers] = useState<string[]>([]);
    const [users, setUsers] = useState<SelectableUser[]>([]);
    const [selectedServer, setSelectedServer] = useState("");
    const [selectedUserId, setSelectedUserId] = useState("");
    const [content, setContent] = useState("");

    useEffect(() => {
        // Fetch Servers
        fetch("/api/server/list").then(res => res.json()).then(data => { if (data.servers) setServers(data.servers); });
    }, []);

    useEffect(() => {
        if (selectedServer) {
            fetch(`/api/user/list-by-server?serverCode=${encodeURIComponent(selectedServer)}`)
                .then(res => res.json()).then(data => { if (data.users) setUsers(data.users); });
        } else {
            setUsers([]);
        }
    }, [selectedServer]);

    const fetchMessages = (type: string) => {
        setLoading(true);
        fetch(`/api/message/list?type=${type}`)
            .then(res => res.json())
            .then(data => {
                if (data.messages) setMessages(data.messages);
                setLoading(false);
            });
    };

    const fetchBlocked = () => {
        setLoading(true);
        fetch("/api/message/blocked")
            .then(res => res.json())
            .then(data => {
                if (data.blockedUsers) setBlockedUsers(data.blockedUsers);
                setLoading(false);
            });
    };

    useEffect(() => {
        if (activeTab === "blocked") {
            fetchBlocked();
        } else if (activeTab !== "compose") {
            fetchMessages(activeTab);
        }
    }, [activeTab]);

    const handleSend = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedUserId) return alert("Select a receiver");

        const res = await fetch("/api/message/send", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ receiverId: selectedUserId, content })
        });
        const data = await res.json();
        if (res.ok) {
            alert("Sent!");
            setSelectedServer("");
            setSelectedUserId("");
            setContent("");
            setActiveTab("outbox");
        } else {
            alert(data.error);
        }
    };

    const handleBlock = async (userId: string) => {
        if (!confirm("Block this user? You will not receive messages from them.")) return;
        const res = await fetch("/api/message/block", {
            method: "POST", headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ userId })
        });
        if (res.ok) {
            alert("Blocked");
            if (activeTab === "blocked") fetchBlocked();
            else fetchMessages(activeTab); // refresh to potentially hide or just update
        } else {
            alert("Failed to block");
        }
    };

    const handleUnblock = async (userId: string) => {
        const res = await fetch("/api/message/unblock", {
            method: "POST", headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ userId })
        });
        if (res.ok) fetchBlocked();
    };

    return (
        <div className="min-h-screen bg-slate-900 text-white p-8">
            <div className="max-w-4xl mx-auto bg-slate-800 rounded-lg border border-slate-700 min-h-[600px] flex flex-col">
                <div className="flex border-b border-slate-700">
                    <button
                        onClick={() => setActiveTab("inbox")}
                        className={`flex-1 py-4 font-bold ${activeTab === "inbox" ? "text-sky-400 border-b-2 border-sky-400 bg-slate-700/50" : "text-slate-400 hover:text-white"}`}
                    >
                        Inbox
                    </button>
                    <button
                        onClick={() => setActiveTab("outbox")}
                        className={`flex-1 py-4 font-bold ${activeTab === "outbox" ? "text-violet-400 border-b-2 border-violet-400 bg-slate-700/50" : "text-slate-400 hover:text-white"}`}
                    >
                        Outbox
                    </button>
                    <button
                        onClick={() => setActiveTab("compose")}
                        className={`flex-1 py-4 font-bold ${activeTab === "compose" ? "text-emerald-400 border-b-2 border-emerald-400 bg-slate-700/50" : "text-slate-400 hover:text-white"}`}
                    >
                        Compose
                    </button>
                    <button
                        onClick={() => setActiveTab("blocked")}
                        className={`flex-1 py-4 font-bold ${activeTab === "blocked" ? "text-rose-400 border-b-2 border-rose-400 bg-slate-700/50" : "text-slate-400 hover:text-white"}`}
                    >
                        Blocked
                    </button>
                </div>

                <div className="p-6 flex-1">
                    {activeTab === "compose" ? (
                        <form onSubmit={handleSend} className="space-y-4 max-w-lg mx-auto mt-8">
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm text-slate-400 mb-1">Server</label>
                                    <select
                                        className="w-full bg-slate-700 p-2 rounded text-white border border-slate-600"
                                        value={selectedServer}
                                        onChange={e => { setSelectedServer(e.target.value); setSelectedUserId(""); }}
                                        required
                                    >
                                        <option value="">Select Server</option>
                                        {servers.map(s => <option key={s} value={s}>{s}</option>)}
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-sm text-slate-400 mb-1">Receiver</label>
                                    <select
                                        className="w-full bg-slate-700 p-2 rounded text-white border border-slate-600 disabled:opacity-50"
                                        value={selectedUserId}
                                        onChange={e => setSelectedUserId(e.target.value)}
                                        required
                                        disabled={!selectedServer}
                                    >
                                        <option value="">Select User</option>
                                        {users.map(u => (
                                            <option key={u.id} value={u.id}>{u.displayName}</option>
                                        ))}
                                    </select>
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm text-slate-400 mb-1">Message</label>
                                <textarea
                                    className="w-full bg-slate-700 p-2 rounded text-white h-32 border border-slate-600"
                                    placeholder="Type your message..."
                                    value={content}
                                    onChange={e => setContent(e.target.value)}
                                    required
                                />
                            </div>
                            <button className="w-full bg-emerald-600 hover:bg-emerald-500 py-2 rounded font-bold text-white transition-colors">Send Message</button>
                        </form>
                    ) : activeTab === "blocked" ? (
                        <div className="space-y-2">
                            {loading ? <p>Loading...</p> : blockedUsers.map(u => (
                                <div key={u.id} className="p-4 bg-slate-700/30 rounded border border-slate-700 flex justify-between items-center">
                                    <span className="font-bold text-white">{u.displayName} ({u.serverCode})</span>
                                    <button
                                        onClick={() => handleUnblock(u.id)}
                                        className="px-3 py-1 bg-slate-600 hover:bg-slate-500 rounded text-sm text-white"
                                    >
                                        Unblock
                                    </button>
                                </div>
                            ))}
                            {!loading && blockedUsers.length === 0 && <p className="text-center text-slate-500 py-12">No blocked users.</p>}
                        </div>
                    ) : (
                        <div className="space-y-2">
                            {loading ? <p>Loading...</p> : messages.map(msg => (
                                <div key={msg.id} className="p-4 bg-slate-700/30 rounded border border-slate-700 hover:bg-slate-700/50 group relative">
                                    <div className="flex justify-between items-center mb-1">
                                        <span className="font-bold text-white">
                                            {activeTab === 'inbox' ? `From: ${msg.sender?.displayName || "Unknown"}` : `To: ${msg.receiver?.displayName || "Unknown"}`}
                                        </span>
                                        <div className="flex items-center gap-2">
                                            <span className="text-xs text-slate-500">{new Date(msg.createdAt).toLocaleString()}</span>
                                            {activeTab === 'inbox' && (
                                                <button
                                                    onClick={(e) => { e.stopPropagation(); handleBlock(msg.senderId); }}
                                                    className="opacity-0 group-hover:opacity-100 px-2 py-0.5 bg-rose-900/50 text-rose-400 text-xs rounded hover:bg-rose-900 hover:text-white transition-all"
                                                >
                                                    Block
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                    <p className="text-slate-300 line-clamp-2">{msg.content}</p>
                                </div>
                            ))}
                            {!loading && messages.length === 0 && <p className="text-center text-slate-500 py-12">No messages.</p>}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import { getServerSession } from "next-auth";
import Link from "next/link";
import { authOptions } from "@/lib/auth";
import { PrismaClient } from "@prisma/client";
import PostList from "@/components/PostList";
import SearchWidget from "@/components/SearchWidget";
import QuickMenu from "@/components/QuickMenu";
import NotificationTestUI from "@/components/NotificationTestUI";

const prisma = new PrismaClient();

async function getLatestPosts() {
  return prisma.post.findMany({
    take: 20, // Increase count for dense view
    orderBy: { createdAt: "desc" },
    where: { board: { isGlobal: true } },
    include: {
      author: { select: { displayName: true, serverCode: true, globalRole: true } },
      board: { select: { title: true, slug: true } },
      alliance: { select: { name: true } },
      _count: { select: { comments: true } }
    }
  });
}

async function getBestPosts() {
  // Logic: Most likes in last 7 days? For now: Top 5 by likeCount all time
  return prisma.post.findMany({
    take: 5,
    orderBy: { likeCount: "desc" },
    where: { board: { isGlobal: true } },
    include: {
      author: { select: { displayName: true, serverCode: true, globalRole: true } },
      board: { select: { title: true, slug: true } },
      alliance: { select: { name: true } },
      _count: { select: { comments: true } }
    }
  });
}

async function getRecentComments() {
  return prisma.comment.findMany({
    take: 5,
    orderBy: { createdAt: "desc" },
    where: {
      post: {
        board: { isGlobal: true }
      }
    },
    include: {
      author: { select: { displayName: true, serverCode: true } },
      post: { select: { id: true, title: true } }
    }
  });
}

interface FeedPost {
  id: string;
  title: string;
  content: string;
  createdAt: string;
  likeCount: number;
  author: { displayName: string | null; serverCode: string | null; globalRole: string };
  board: { title: string; slug: string } | null;
  alliance: { name: string } | null;
  category: string | null;
  _count: { comments: number; reactions?: number; };
}

interface FeedComment {
  id: string;
  content: string;
  post: { id: string; title: string };
  author: { displayName: string | null; serverCode: string | null };
  createdAt: Date;
}

export default async function Home() {
  const session = await getServerSession(authOptions);
  let posts: FeedPost[] = [];
  let bestPosts: FeedPost[] = [];
  let recentComments: FeedComment[] = [];

  try {
    const [latest, best, comments] = await Promise.all([getLatestPosts(), getBestPosts(), getRecentComments()]);
    // Map dates to strings for client components
    posts = latest.map(p => ({ ...p, createdAt: p.createdAt.toISOString() })) as unknown as FeedPost[];
    bestPosts = best.map(p => ({ ...p, createdAt: p.createdAt.toISOString() })) as unknown as FeedPost[];
    recentComments = comments;
  } catch (e) { console.error(e); }

  return (
    <div className="min-h-screen bg-wos-bg text-slate-300 font-sans text-sm">
      {/* Header */}


      <div className="max-w-[1400px] mx-auto p-4 grid grid-cols-1 lg:grid-cols-12 gap-6 mt-4">

        {/* Left Sidebar (Login / Nav) - Span 3 */}
        <aside className="lg:col-span-3 space-y-4">
          {/* Login Widget */}
          <div className="bg-wos-surface rounded-xl border border-white/5 p-4 shadow-lg backdrop-blur-sm">
            {session ? (
              <div>
                <div className="flex items-center gap-3 mb-4">
                  <div className="w-10 h-10 rounded-full bg-gradient-to-br from-violet-500 to-fuchsia-500 flex items-center justify-center text-white font-bold text-lg">
                    {session.user?.displayName?.[0] || "U"}
                  </div>
                  <div>
                    <div className="font-bold text-white">{session.user?.displayName}</div>
                    <div className="text-xs text-slate-500">{session.user?.serverCode}</div>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-2 text-center text-xs text-slate-400 border-t border-slate-700 pt-3">
                  <Link href="/messages" className="hover:text-white hover:bg-slate-700 p-2 rounded">
                    📩 Messages
                  </Link>
                  <Link href="/auth/onboarding" className="hover:text-white hover:bg-slate-700 p-2 rounded">
                    ⚙️ Settings
                  </Link>
                </div>
                {session.user?.role === "ADMIN" && (
                  <Link href="/admin" className="block text-center mt-2 bg-rose-500/10 text-rose-400 py-2 rounded border border-rose-500/20 hover:bg-rose-500/20 transition-colors">
                    Admin Dashboard
                  </Link>
                )}
              </div>
            ) : (
              <div className="text-center">
                <p className="text-slate-400 mb-4">Join the community to discuss strategy and coordinate with alliances.</p>
                <Link href="/auth/signin" className="block w-full bg-sky-600 hover:bg-sky-500 text-white font-bold py-2 rounded transition-colors">
                  Sign In / Sign Up
                </Link>
              </div>
            )}
          </div>

          {/* Quick Menu */}
          <QuickMenu />
        </aside>

        {/* Main Content (Feed) - Span 6 */}
        <main className="lg:col-span-6 space-y-6">

          {/* Best Posts Section */}
          <section>
            <div className="flex items-center gap-2 mb-3 px-1">
              <span className="text-xl">🔥</span>
              <h2 className="text-lg font-bold font-heading bg-gradient-to-r from-fire-400 to-amber-500 bg-clip-text text-transparent">Weekly Best</h2>
            </div>
            <div className="bg-wos-surface rounded-xl border border-white/5 p-1 shadow-lg overflow-hidden">
              <div className="bg-black/20 p-3 space-y-2">
                {bestPosts.map((post, idx) => (
                  <Link key={post.id} href={`/posts/${post.id}`} className="flex items-start gap-3 p-2 rounded-lg hover:bg-white/5 transition-colors group">
                    <span className={`w-6 h-6 rounded flex items-center justify-center font-bold text-xs shrink-0 ${idx < 3 ? 'bg-gradient-to-br from-amber-500 to-orange-600 text-white shadow-lg shadow-orange-500/20' : 'bg-slate-700 text-slate-400'}`}>
                      {idx + 1}
                    </span>
                    <div className="min-w-0 flex-1">
                      <div className="font-medium text-slate-200 truncate group-hover:text-ice-400 transition-colors text-sm">{post.title}</div>
                      <div className="text-[10px] text-slate-500 flex items-center gap-2 mt-0.5">
                        <span>{post.board?.title || "Global"}</span>
                        <span>•</span>
                        <span className="text-amber-500/80">👍 {post.likeCount}</span>
                      </div>
                    </div>
                  </Link>
                ))}
                {bestPosts.length === 0 && <div className="text-slate-500 text-center py-4 text-xs">No trending posts yet.</div>}
              </div>
            </div>
          </section>

          {/* Latest Posts Feed */}
          <section>
            <div className="flex items-center justify-between mb-3 px-1">
              <h2 className="text-lg font-bold text-ice-400 font-heading">Recent Posts</h2>
              <Link href="/boards" className="text-xs text-slate-500 hover:text-ice-400 transition-colors uppercase font-bold tracking-wider">More +</Link>
            </div>
            <PostList posts={posts} />
            <NotificationTestUI />
          </section>
        </main>

        {/* Right Sidebar (Widgets) - Span 3 */}
        <aside className="lg:col-span-3 space-y-4">
          {/* Search Widget */}
          <SearchWidget />

          {/* Banner / Ad Placeholder */}
          <div className="bg-wos-surface rounded-xl border border-white/5 p-4 min-h-[200px] flex items-center justify-center text-slate-600 text-xs text-center shadow-lg">
            WOS Community<br />Space for Banners
          </div>

          {/* Recent Comments */}
          <div className="bg-wos-surface rounded-xl border border-white/5 p-4 shadow-lg">
            <h3 className="font-bold text-white mb-3 flex items-center gap-2">
              <span className="w-1 h-4 bg-ice-500 rounded-full" /> New Comments
            </h3>
            <div className="text-xs text-slate-500 space-y-3">
              {recentComments.map(comment => (
                <div key={comment.id} className="group border-b border-white/5 pb-2 last:border-0 last:pb-0">
                  <div className="flex justify-between items-center mb-1">
                    <span className="text-slate-300 font-bold">{comment.author?.displayName}</span>
                    <span className="text-[10px] text-slate-600">{new Date(comment.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                  </div>
                  <Link href={`/posts/${comment.post.id}`} className="block text-slate-400 hover:text-white truncate mb-1">
                    {comment.content}
                  </Link>
                  <Link href={`/posts/${comment.post.id}`} className="text-sky-600 hover:underline text-[10px] block truncate">
                    on "{comment.post.title}"
                  </Link>
                </div>
              ))}
              {recentComments.length === 0 && <div className="text-center italic text-slate-600">No comments yet.</div>}
            </div>
          </div>
        </aside>

      </div>
    </div>
  );
}

"use client";

import { useSession, signOut } from "next-auth/react";
import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import Image from "next/image";
import { Loader2, Save, LogOut, Shield, Lock } from "lucide-react";

interface UserProfile {
    name: string;
    email: string;
    image: string;
    displayName: string | null;
    serverCode: string | null;
    memberships: Array<{
        role: string;
        alliance: {
            id: string;
            name: string;
            description: string | null;
        }
    }>;
}

export default function ProfilePage() {
    const { data: session, status } = useSession();
    const router = useRouter();

    const [profile, setProfile] = useState<UserProfile | null>(null);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);

    // Form States
    const [displayName, setDisplayName] = useState("");
    const [serverCode, setServerCode] = useState("");

    useEffect(() => {
        if (status === "unauthenticated") {
            router.push("/auth/signin");
            return;
        }

        if (status === "authenticated") {
            fetch("/api/user/profile")
                .then(res => {
                    if (!res.ok) throw new Error("Failed");
                    return res.json();
                })
                .then(data => {
                    setProfile(data.user);
                    setDisplayName(data.user.displayName || "");
                    setServerCode(data.user.serverCode || "");
                    setLoading(false);
                })
                .catch(err => {
                    console.error(err);
                    setLoading(false);
                });
        }
    }, [status, router]);

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setSaving(true);
        try {
            const res = await fetch("/api/user/profile", {
                method: "PUT",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ displayName, serverCode })
            });

            if (res.ok) {
                alert("Profile Updated!");
                // Optionally reload session or re-fetch
            } else {
                alert("Update failed");
            }
        } catch (error) {
            alert("Error saving");
        }
        setSaving(false);
    };

    if (loading || status === "loading") {
        return (
            <div className="min-h-screen bg-wos-bg flex items-center justify-center">
                <Loader2 className="animate-spin text-ice-500" size={48} />
            </div>
        );
    }

    if (!profile) return null;

    return (
        <div className="min-h-screen bg-wos-bg p-4 md:p-8">
            <div className="max-w-4xl mx-auto space-y-8">

                {/* Header Card */}
                <div className="bg-gradient-to-r from-wos-surface to-slate-900 border border-slate-700 rounded-2xl p-8 flex flex-col md:flex-row items-center gap-8 shadow-2xl relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-64 h-64 bg-ice-500/5 rounded-full blur-3xl -mr-20 -mt-20 pointer-events-none"></div>

                    <div className="relative">
                        <div className="w-24 h-24 md:w-32 md:h-32 rounded-full border-4 border-slate-800 shadow-xl overflow-hidden relative z-10">
                            {profile.image ? (
                                <Image src={profile.image} alt="Avatar" fill className="object-cover" />
                            ) : (
                                <div className="w-full h-full bg-slate-700 flex items-center justify-center text-4xl text-slate-400 font-bold">
                                    {profile.name[0]}
                                </div>
                            )}
                        </div>
                        <div className="absolute bottom-0 right-0 bg-ice-500 border-4 border-wos-surface w-8 h-8 rounded-full z-20"></div>
                    </div>

                    <div className="flex-1 text-center md:text-left z-10">
                        <h1 className="text-3xl font-bold font-heading text-white mb-2">{profile.displayName || profile.name}</h1>
                        <div className="flex flex-wrap items-center justify-center md:justify-start gap-4 text-slate-400 text-sm">
                            <span className="bg-slate-800/50 px-3 py-1 rounded-full border border-slate-700">
                                {profile.email}
                            </span>
                            {profile.serverCode && (
                                <span className="bg-fire-500/10 text-fire-400 px-3 py-1 rounded-full border border-fire-500/20">
                                    Server: {profile.serverCode}
                                </span>
                            )}
                        </div>
                    </div>

                    <button
                        onClick={() => signOut({ callbackUrl: "/" })}
                        className="flex items-center gap-2 bg-slate-800 hover:bg-fire-500/10 hover:text-fire-400 hover:border-fire-500/50 text-slate-400 px-4 py-2 rounded-lg border border-slate-700 transition-all z-10"
                    >
                        <LogOut size={18} />
                        <span>Sign Out</span>
                    </button>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

                    {/* Identity Settings */}
                    <div className="lg:col-span-2">
                        <div className="bg-wos-surface border border-slate-700 rounded-xl p-6 shadow-lg">
                            <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
                                <span className="w-2 h-6 bg-ice-500 rounded-full"></span>
                                Identity Settings
                            </h2>

                            <form onSubmit={handleSave} className="space-y-6">
                                <div>
                                    <label className="block text-sm font-bold text-slate-400 mb-2">Email Address (Locked)</label>
                                    <div className="relative">
                                        <input
                                            type="text"
                                            value={profile.email}
                                            disabled
                                            className="w-full bg-slate-900/50 border border-slate-800 rounded-lg px-4 py-3 text-slate-500 cursor-not-allowed pl-10"
                                        />
                                        <Lock className="absolute left-3 top-3.5 text-slate-600" size={18} />
                                    </div>
                                    <p className="text-xs text-slate-600 mt-2 flex items-center gap-1">
                                        <Shield size={12} />
                                        Managed by Google OAuth
                                    </p>
                                </div>
                                <div>
                                    <label className="block text-sm font-bold text-slate-400 mb-2">Display Name (In-Game Name)</label>
                                    <input
                                        type="text"
                                        value={displayName}
                                        onChange={(e) => setDisplayName(e.target.value)}
                                        className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-ice-500 transition-colors"
                                        placeholder="e.g. DarkAcid"
                                    />
                                </div>

                                <div>
                                    <label className="block text-sm font-bold text-slate-400 mb-2">Server Code</label>
                                    <input
                                        type="text"
                                        value={serverCode}
                                        onChange={(e) => setServerCode(e.target.value)}
                                        className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-ice-500 transition-colors"
                                        placeholder="e.g. #2517"
                                    />
                                    <p className="text-xs text-slate-500 mt-2">Used to identify your server region.</p>
                                </div>

                                <div className="pt-4 border-t border-slate-700/50">
                                    <button
                                        type="submit"
                                        disabled={saving}
                                        className="bg-ice-600 hover:bg-ice-500 text-white px-6 py-3 rounded-lg font-bold flex items-center justify-center gap-2 w-full sm:w-auto disabled:opacity-50 transition-all"
                                    >
                                        {saving ? <Loader2 className="animate-spin" size={20} /> : <Save size={20} />}
                                        Save Changes
                                    </button>
                                </div>
                            </form>
                        </div>
                    </div>

                    {/* Alliances Side Panel */}
                    <div className="lg:col-span-1">
                        <div className="bg-wos-surface border border-slate-700 rounded-xl p-6 shadow-lg h-full">
                            <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
                                <Shield className="text-fire-500" />
                                My Alliances
                            </h2>

                            <div className="space-y-4">
                                {profile.memberships.length > 0 ? (
                                    profile.memberships.map((m) => (
                                        <div key={m.alliance.id} className="bg-slate-800/50 p-4 rounded-lg border border-slate-700 hover:border-ice-500/30 transition-colors">
                                            <div className="flex justify-between items-start mb-2">
                                                <h3 className="font-bold text-ice-400">{m.alliance.name}</h3>
                                                <span className="text-xs font-bold uppercase bg-slate-900 px-2 py-1 rounded text-slate-400">
                                                    {m.role}
                                                </span>
                                            </div>
                                            <p className="text-xs text-slate-500 line-clamp-2">
                                                {m.alliance.description || "No description"}
                                            </p>
                                        </div>
                                    ))
                                ) : (
                                    <div className="text-center py-8 text-slate-500">
                                        <p className="mb-4">You haven't joined any alliances yet.</p>
                                        <a href="/alliances" className="text-ice-500 text-sm hover:underline">Browse Alliances</a>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

