            const query = new URLSearchParams({ date: dateStr });
            if (allianceId) query.append("allianceId", allianceId);

            const res = await fetch(`/api/ministry/reservations?${query.toString()}`);
            const data = await res.json();
            if (data.reservations) {
                setReservations(data.reservations);
            }
        } catch (e) {
            console.error(e);
        }
        setLoading(false);
    };

    useEffect(() => {
        fetchData();
    }, [activeDay]); // Re-fetch when day changes

    const handleReservationClick = (res: MinistryReservation) => {
        setSelectedReservation(res);
        setIsDetailOpen(true);
    };

    const handleBulkApprove = async () => {
        if (!confirm("Are you sure you want to approve all valid non-conflicting applications for this day?")) return;
        setLoading(true);
        try {
            const date = addDays(startOfSvS, activeDay);
            const dateStr = format(date, "yyyy-MM-dd");
            const res = await fetch('/api/ministry/reservations/bulk-approve', {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ allianceId, date: dateStr })
            });

            if (res.ok) {
                alert("Bulk approval successful!");
                fetchData();
            } else {
                const data = await res.json();
                alert(data.error || "Failed to bulk approve");
            }
        } catch (e) {
            console.error(e);
            alert("Error during bulk approval");
        }
        setLoading(false);
    };

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                {/* Day Tabs */}
                <div className="flex gap-2 overflow-x-auto pb-2">
                    {DAYS.map((d, idx) => (
                        <button
                            key={idx}
                            onClick={() => setActiveDay(idx)}
                            className={`
                                px-6 py-3 rounded-xl font-bold transition-all whitespace-nowrap
                                ${activeDay === idx
                                    ? "bg-ice-500 text-white shadow-lg shadow-ice-500/20"
                                    : "bg-wos-surface border border-slate-700 text-slate-400 hover:text-white hover:bg-slate-800"}
                            `}
                        >
                            {d.label}
                        </button>
                    ))}
                </div>

                {/* Admin Bulk Approve Button */}
                {canManage && (
                    <button
                        onClick={handleBulkApprove}
                        disabled={loading}
                        className="bg-emerald-600 hover:bg-emerald-500 text-white px-4 py-2 rounded-lg font-bold shadow-lg shadow-emerald-900/20 transition-all flex items-center gap-2"
                    >
                        {loading ? <span className="animate-spin text-xl">↻</span> : <span>✓</span>}
                        Approve All Valid
                    </button>
                )}
            </div>

            {/* Recommendation Banner */}
            {activeDay === 3 ? ( // Day 4
                <div className="bg-gradient-to-r from-cyan-900/50 to-slate-900 border border-cyan-500/30 p-4 rounded-xl flex items-center gap-4">
                    <div className="p-3 bg-cyan-500/10 rounded-full text-cyan-400">
                        <GraduationCap size={24} />
                    </div>
                    <div>
                        <h3 className="font-bold text-cyan-100">Recommendation: Minister of Education</h3>
                        <p className="text-sm text-cyan-300/70">Day 4 focuses on Troop Training. Prioritize Education buffs.</p>
                    </div>
                </div>
            ) : (
                <div className="bg-gradient-to-r from-amber-900/50 to-slate-900 border border-amber-500/30 p-4 rounded-xl flex items-center gap-4">
                    <div className="p-3 bg-amber-500/10 rounded-full text-amber-400">
                        <Crown size={24} />
                    </div>
                    <div>
                        <h3 className="font-bold text-amber-100">Recommendation: Vice President</h3>
                        <p className="text-sm text-amber-300/70">General speedups for Construction and Research are most effective today.</p>
                    </div>
                </div>
            )}

            {/* The Grid for Active Day */}
            <div className="bg-wos-surface border border-slate-700 rounded-xl overflow-hidden shadow-xl overflow-x-auto">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="bg-slate-900 border-b border-slate-700">
                            <th className="p-4 w-24 sticky left-0 bg-slate-900 z-10 border-r border-slate-700 text-slate-500 font-mono text-xs">UTC</th>
                            {MINISTERS.map(m => (
                                <th key={m.id} className="p-4 min-w-[180px] border-r border-slate-800 last:border-0">
                                    <div className="flex items-center gap-2">
                                        <m.icon size={18} className={m.color} />
                                        <span className="text-sm font-bold text-slate-300">{m.name}</span>
                                    </div>
                                </th>
                            ))}
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-800">
                        {/* 24 Hours x 2 (30 min slots) = 48 rows */}
                        {Array.from({ length: 48 }).map((_, slotIdx) => {
                            const hour = Math.floor(slotIdx / 2);
                            const minute = (slotIdx % 2) * 30;
                            const timeStr = `${hour.toString().padStart(2, '0')}:${minute.toString().padStart(2, '0')}`;

                            return (
                                <tr key={slotIdx} className="hover:bg-slate-800/30 transition-colors group">
                                    <td className="p-3 border-r border-slate-700/50 text-slate-500 font-mono text-xs sticky left-0 bg-wos-surface group-hover:bg-slate-800/30 z-10">
                                        {timeStr}
                                    </td>
                                    {MINISTERS.map(m => {
                                        // Find reservation for this slot & position
                                        // Simple match by StartTime (Hour:Minute match)
                                        // Since we store exact DateTimes, we compare Time parts for the CURRENT DAY view
                                        const slotRes = reservations.find(r => {
                                            if (r.position !== m.id) return false;
                                            const rDate = new Date(r.startTime);
                                            return rDate.getHours() === hour && rDate.getMinutes() === minute;
                                        });

                                        return (
                                            <td key={m.id} className="p-1 border-r border-slate-800 last:border-0 relative h-10">
                                                {slotRes ? (
                                                    <button
                                                        onClick={() => handleReservationClick(slotRes)}
                                                        className={`w-full h-full rounded flex items-center gap-2 px-2 transition-all text-left relative overflow-hidden
                                                            ${slotRes.status === 'APPROVED' ? 'bg-green-500/20 border border-green-500/30 hover:bg-green-500/30' :
                                                                slotRes.status === 'REJECTED' ? 'bg-red-500/10 border border-red-500/20 opacity-60' :
                                                                    'bg-amber-500/10 border border-amber-500/30 hover:bg-amber-500/20'}
                                                        `}
                                                    >
                                                        {/* Avatar */}
                                                        <div className="w-6 h-6 rounded-full bg-slate-800 shrink-0 relative overflow-hidden">
                                                            {slotRes.user.image ? (
                                                                <Image src={slotRes.user.image} alt="U" fill className="object-cover" />
                                                            ) : (
                                                                <span className="flex items-center justify-center w-full h-full text-[10px] text-white font-bold">{slotRes.user.name?.[0]}</span>
                                                            )}
                                                        </div>
                                                        <span className="text-xs font-bold text-white truncate">{slotRes.user.displayName || slotRes.user.name}</span>

                                                        {/* Status Dot */}
                                                        {slotRes.status === 'PENDING' && <div className="absolute top-1 right-1 w-1.5 h-1.5 bg-amber-400 rounded-full animate-pulse"></div>}
                                                    </button>
                                                ) : (
                                                    <button
                                                        onClick={() => handleSlotClick(m.id, activeDay, hour, minute)}
                                                        className="w-full h-full rounded hover:bg-ice-500/10 hover:border hover:border-ice-500/30 transition-all flex items-center justify-center text-xs text-slate-600 hover:text-ice-400 opacity-0 group-hover:opacity-100 focus:opacity-100"
                                                    >
                                                        <span>+</span>
                                                    </button>
                                                )}
                                            </td>
                                        );
                                    })}
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </div>

            <ApplicationModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                position={selectedPosition}
                day={selectedDayLabel}
                date={selectedDate}
                slotTime={selectedSlotStr}
                onSuccess={() => {
                    fetchData(); // Refresh grid
                }}
            />

            <ReservationDetailModal
                isOpen={isDetailOpen}
                onClose={() => setIsDetailOpen(false)}
                reservation={selectedReservation}
                onUpdate={fetchData}
                canManage={canManage}
            />
        </div>
    );
}

"use client";

import { useSession } from "next-auth/react";
import { useState } from "react";
import { X, Trash2 } from "lucide-react";
import Image from "next/image";

interface Props {
    isOpen: boolean;
    onClose: () => void;
    reservation: any;
    onUpdate: () => void;
    canManage?: boolean;
}

export default function ReservationDetailModal({ isOpen, onClose, reservation, onUpdate, canManage = false }: Props) {
    const { data: session } = useSession();
    const [processing, setProcessing] = useState(false);

    if (!isOpen || !reservation) return null;

    // Admin or R4/R5 logic provided via canManage
    const hasPermission = canManage || session?.user?.globalRole === "ADMIN" || session?.user?.isApprovedLeader;

    const handleStatus = async (status: "APPROVED" | "REJECTED") => {
        setProcessing(true);
        try {
            const res = await fetch(`/api/ministry/reservations/${reservation.id}`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ status })
            });
            if (res.ok) {
                onUpdate();
                onClose();
            }
        } catch (e) {
            alert("Action failed");
        }
        setProcessing(false);
    };

    const handleDelete = async () => {
        if (!confirm("Cancel this reservation?")) return;
        setProcessing(true);
        try {
            const res = await fetch(`/api/ministry/reservations/${reservation.id}`, {
                method: "DELETE"
            });
            if (res.ok) {
                onUpdate();
                onClose();
            }
        } catch (e) {
            alert("Action failed");
        }
        setProcessing(false);
    };

    const resources = reservation.resourceData || {};

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm">
            <div className="bg-white rounded-2xl w-full max-w-sm overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200">
                {/* Header */}
                <div className={`p-4 text-center border-b relative ${reservation.status === 'APPROVED' ? 'bg-green-50' : reservation.status === 'REJECTED' ? 'bg-red-50' : 'bg-amber-50'}`}>
                    <button onClick={onClose} className="absolute right-3 top-3 text-slate-400 hover:text-slate-600">
                        <X size={20} />
                    </button>

                    <span className={`inline-block px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider mb-2
                        ${reservation.status === 'APPROVED' ? 'bg-green-200 text-green-700' : reservation.status === 'REJECTED' ? 'bg-red-200 text-red-700' : 'bg-amber-200 text-amber-700'}
                    `}>
                        {reservation.status}
                    </span>

                    <h3 className="font-bold text-slate-800">{reservation.position.replace(/_/g, " ")}</h3>
                    <div className="text-sm font-mono text-slate-500 mt-1">
                        {new Date(reservation.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} UTC
                    </div>
                </div>

                <div className="p-6 space-y-6">
                    {/* User Info */}
                    <div className="flex items-center gap-4">
                        <div className="w-12 h-12 rounded-full bg-slate-200 relative overflow-hidden border border-slate-300">
                            {reservation.user.image ? (
                                <Image src={reservation.user.image} alt={reservation.user.name} fill className="object-cover" />
                            ) : (
                                <div className="flex items-center justify-center h-full font-bold text-slate-400">{reservation.user.name?.[0]}</div>
                            )}
                        </div>
                        <div>
                            <div className="font-bold text-slate-800">{reservation.user.displayName || reservation.user.name}</div>
                            <div className="text-xs text-slate-500 font-mono">ID: {reservation.user.id.substring(0, 8)}</div>
                        </div>
                    </div>

                    {/* Resources */}
                    <div className="bg-slate-50 rounded-lg p-3 border border-slate-200 text-sm space-y-2">
                        <h4 className="text-xs font-bold text-slate-400 uppercase">Resource Commitment</h4>
                        {Object.entries(resources).length > 0 ? (
                            <div className="grid grid-cols-2 gap-2">
                                {Object.entries(resources).map(([key, val]) => (
                                    <div key={key}>
                                        <span className="text-slate-500 text-xs block">{key}</span>
                                        <span className="font-mono font-bold text-slate-700">{val as React.ReactNode}</span>
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div className="text-slate-400 italic text-xs">No resources specified</div>
                        )}
                    </div>

                    {/* Admin Actions */}
                    {hasPermission && reservation.status === "PENDING" && (
                        <div className="grid grid-cols-2 gap-3 pt-2">
                            <button
                                onClick={() => handleStatus("REJECTED")}
                                disabled={processing}
                                className="py-2 bg-slate-100 hover:bg-red-100 text-slate-600 hover:text-red-600 font-bold rounded flex items-center justify-center gap-1 transition-colors"
                            >
                                Reject
                            </button>
                            <button
                                onClick={() => handleStatus("APPROVED")}
                                disabled={processing}
                                className="py-2 bg-green-500 hover:bg-green-600 text-white font-bold rounded flex items-center justify-center gap-1 transition-colors"
                            >
                                Approve
                            </button>
                        </div>
                    )}

                    {/* Delete (Owner or Admin) */}
                    {(hasPermission || session?.user.id === reservation.userId) && (
                        <button
                            onClick={handleDelete}
                            disabled={processing}
                            className="w-full py-2 text-red-400 hover:bg-red-50 hover:text-red-500 rounded text-xs font-bold flex items-center justify-center gap-1 transition-colors"
                        >
                            <Trash2 size={14} /> Cancel Reservation
                        </button>
                    )}
                </div>
            </div>
        </div>
    );
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useSession } from "next-auth/react";
import { useEffect, useState } from "react";
import { ChevronDown } from "lucide-react";
import GlobalClock from "./Clock";
import NotificationBell from "./NotificationBell";

export default function Navbar() {
    const pathname = usePathname();
    const { data: session } = useSession();
    const [boards, setBoards] = useState<any[]>([]);

    useEffect(() => {
        // Fetch Global Boards with simple cache busting
        fetch("/api/board/list", { cache: "no-store" })
            .then(res => res.json())
            .then(data => {
                if (data.boards) setBoards(data.boards);
            })
            .catch(err => console.error("Nav fetch error:", err));
    }, []);

    const isActive = (path: string) => pathname === path || (path !== "/" && pathname.startsWith(path));

    return (
        <header className="sticky top-0 z-50 w-full backdrop-blur-md bg-wos-bg/90 border-b border-ice-500/10 shadow-[0_4px_30px_rgba(0,0,0,0.1)]">
            <div className="max-w-[1400px] mx-auto px-4 h-16 flex items-center justify-between">
                <div className="flex items-center gap-2 shrink-0">
                    <Link href="/" className="flex items-center gap-2 group">
                        <div className="w-8 h-8 rounded bg-gradient-to-br from-ice-400 to-ice-600 flex items-center justify-center font-bold text-white shadow-[0_0_10px_rgba(56,189,248,0.5)] group-hover:shadow-[0_0_20px_rgba(56,189,248,0.8)] transition-all">
                            W
                        </div>
                        <span className="text-xl font-bold font-heading text-white tracking-tight group-hover:text-ice-400 transition-colors hidden sm:inline">
                            WOS <span className="text-ice-500">Community</span>
                        </span>
                    </Link>

                    {/* Mobile Clock (Next to Logo) */}
                    <div className="md:hidden scale-[0.75] origin-left ml-2">
                        <GlobalClock />
                    </div>
                </div>

                {/* Desktop Nav */}
                <nav className="hidden md:flex items-center gap-1 flex-1 justify-start ml-8">
                    <Link
                        href="/"
                        className={`relative px-4 py-2 text-sm font-bold transition-colors hover:text-ice-400 ${isActive("/") ? "text-ice-400" : "text-slate-300"}`}
                    >
                        Home
                        {isActive("/") && <span className="absolute bottom-0 left-0 w-full h-0.5 bg-ice-500 shadow-[0_-2px_6px_rgba(56,189,248,0.5)]" />}
                    </Link>

                    {/* Boards Dropdown */}
                    <div className="relative group">
                        <Link
                            href="/boards"
                            className={`flex items-center gap-1 px-4 py-2 text-sm font-bold transition-colors hover:text-ice-400 ${pathname.startsWith("/boards") ? "text-ice-400" : "text-slate-300"}`}
                        >
                            Boards <ChevronDown size={14} />
                            {pathname.startsWith("/boards") && <span className="absolute bottom-0 left-0 w-full h-0.5 bg-ice-500 shadow-[0_-2px_6px_rgba(56,189,248,0.5)]" />}
                        </Link>

                        {/* Dropdown Menu */}
                        <div className="absolute top-full left-0 w-56 pt-2 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 transform translate-y-2 group-hover:translate-y-0">
                            <div className="bg-slate-800 border border-slate-700 rounded-lg shadow-xl overflow-hidden py-1">
                                {boards && boards.length > 0 ? boards.map((board) => (
                                    <Link
                                        key={board.id}
                                        href={`/boards/${board.slug}`}
                                        className={`block px-4 py-2 text-sm font-medium hover:bg-slate-700/50 hover:text-ice-400 transition-colors ${isActive(`/boards/${board.slug}`) ? "text-ice-400 bg-slate-700/30" : "text-slate-400"}`}
                                    >
                                        {board.title}
                                    </Link>
                                )) : <div className="px-4 py-2 text-xs text-slate-500">No boards available</div>}
                            </div>
                        </div>
                    </div>

                    <Link
                        href="/alliances"
                        className={`relative px-4 py-2 text-sm font-bold transition-colors hover:text-ice-400 ${isActive("/alliances") ? "text-ice-400" : "text-slate-300"}`}
                    >
                        Alliances
                        {isActive("/alliances") && <span className="absolute bottom-0 left-0 w-full h-0.5 bg-ice-500 shadow-[0_-2px_6px_rgba(56,189,248,0.5)]" />}
                    </Link>
                    <Link
                        href="/calendar"
                        className={`relative px-4 py-2 text-sm font-bold transition-colors hover:text-ice-400 ${isActive("/calendar") ? "text-ice-400" : "text-slate-300"}`}
                    >
                        Calendar
                        {isActive("/calendar") && <span className="absolute bottom-0 left-0 w-full h-0.5 bg-ice-500 shadow-[0_-2px_6px_rgba(56,189,248,0.5)]" />}
                    </Link>
                    {/* Admin Link */}
                    {session?.user?.role === "ADMIN" && (
                        <Link
                            href="/admin"
                            className="text-xs bg-rose-600/20 text-rose-400 border border-rose-500/50 px-3 py-1 rounded ml-2 hover:bg-rose-600/40 transition-colors whitespace-nowrap font-bold"
                        >
                            Admin Panel
                        </Link>
                    )}
                </nav>

                {/* Right Side */}
                <div className="flex items-center gap-4 shrink-0">
                    <NotificationBell />
                    <div className="hidden lg:block scale-90 origin-right">
                        <GlobalClock />
                    </div>

                    {session ? (
                        <Link href="/profile" className="flex items-center gap-2 hover:bg-white/5 px-2 py-1 rounded transition-colors group">
                            {session.user?.image ? (
                                <img src={session.user.image} alt="Profile" className="w-8 h-8 rounded-full border border-white/10 ring-2 ring-transparent group-hover:ring-ice-500/50 transition-all object-cover" />
                            ) : (
                                <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-xs font-bold text-white border border-white/10 ring-2 ring-transparent group-hover:ring-ice-500/50 transition-all">
                                    {session.user?.displayName?.[0] || "U"}
                                </div>
                            )}
                        </Link>
                    ) : (
                        <Link
                            href="/auth/signin"
                            className="bg-ice-600 hover:bg-ice-500 text-white px-4 py-2 rounded font-bold text-sm shadow-[0_4px_14px_0_rgba(2,132,199,0.39)] transition-all hover:scale-105 whitespace-nowrap"
                        >
                            Login
                        </Link>
                    )}

                    {/* Mobile Menu Toggle */}
                    <MobileMenu boards={boards} isActive={isActive} session={session} />
                </div>
            </div>
        </header >
    );
}

function MobileMenu({ boards, isActive, session }: { boards: any[], isActive: (p: string) => boolean, session: any }) {
    const [isOpen, setIsOpen] = useState(false);
    const pathname = usePathname();

    // Close menu when path changes
    useEffect(() => {
        setIsOpen(false);
    }, [pathname]);

    return (
        <div className="md:hidden">
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="p-2 text-slate-300 hover:text-white transition-colors"
                aria-label="Toggle menu"
            >
                {isOpen ? (
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
                ) : (
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="3" y1="12" x2="21" y2="12"></line><line x1="3" y1="6" x2="21" y2="6"></line><line x1="3" y1="18" x2="21" y2="18"></line></svg>
                )}
            </button>

            {/* Backdrop */}
            {isOpen && <div className="fixed inset-0 top-16 bg-black/50 z-40 backdrop-blur-sm" onClick={() => setIsOpen(false)} />}

            {/* Menu Content */}
            {isOpen && (
                <div className="absolute top-16 left-0 w-full bg-slate-900 border-b border-slate-800 shadow-2xl z-50 p-4 animate-in slide-in-from-top-2 duration-200">
                    <nav className="flex flex-col gap-2">
                        <Link
                            href="/"
                            className={`px-4 py-3 rounded-lg font-bold transition-colors ${isActive("/") ? "bg-slate-800 text-ice-400" : "text-slate-300 hover:bg-slate-800 hover:text-white"}`}
                        >
                            Home
                        </Link>

                        <div className="flex flex-col gap-1">
                            <div className="px-4 py-2 text-xs uppercase font-bold text-slate-500">Boards</div>
                            {boards && boards.length > 0 ? boards.map((board) => (
                                <Link
                                    key={board.id}
                                    href={`/boards/${board.slug}`}
                                    className={`px-4 py-2 ml-2 rounded-lg text-sm font-medium transition-colors ${isActive(`/boards/${board.slug}`) ? "bg-slate-800/50 text-ice-400" : "text-slate-400 hover:text-white hover:bg-slate-800/30"}`}
                                >
                                    # {board.title}
                                </Link>
                            )) : <div className="px-4 py-2 text-sm text-slate-500 italic">No boards available</div>}
                        </div>

                        <Link
                            href="/alliances"
                            className={`px-4 py-3 rounded-lg font-bold transition-colors ${isActive("/alliances") ? "bg-slate-800 text-ice-400" : "text-slate-300 hover:bg-slate-800 hover:text-white"}`}
                        >
                            Alliances
                        </Link>
                        <Link
                            href="/calendar"
                            className={`px-4 py-3 rounded-lg font-bold transition-colors ${isActive("/calendar") ? "bg-slate-800 text-ice-400" : "text-slate-300 hover:bg-slate-800 hover:text-white"}`}
                        >
                            Calendar
                        </Link>

                        {session?.user?.role === "ADMIN" && (
                            <Link
                                href="/admin"
                                className="px-4 py-3 rounded-lg font-bold text-rose-400 bg-rose-500/10 hover:bg-rose-500/20 transition-colors mt-2"
                            >
