"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { Plus, X, Pin } from "lucide-react";
import { useSession } from "next-auth/react";

export default function QuickMenu() {
    const { data: session } = useSession();
    const [pinnedBoards, setPinnedBoards] = useState<any[]>([]);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [allGlobalBoards, setAllGlobalBoards] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);

    // Fetch pinned boards on load
    useEffect(() => {
        if (session) {
            fetch("/api/user/pinned-boards").then(res => res.json()).then(data => {
                if (data.pinnedBoards) setPinnedBoards(data.pinnedBoards);
            });
        }
    }, [session]);

    // Fetch global boards when opening modal
    useEffect(() => {
        if (isModalOpen && allGlobalBoards.length === 0) {
            setLoading(true);
            fetch("/api/board/list?isGlobal=true").then(res => res.json()).then(data => {
                if (data.boards) setAllGlobalBoards(data.boards);
                setLoading(false);
            });
        }
    }, [isModalOpen]);

    const togglePin = async (boardId: string, isPinned: boolean) => {
        // Optimistic Update
        let newPinned = [...pinnedBoards];
        if (isPinned) {
            const board = allGlobalBoards.find(b => b.id === boardId);
            if (board) newPinned.push(board);
        } else {
            newPinned = newPinned.filter(b => b.id !== boardId);
        }
        setPinnedBoards(newPinned);

        await fetch("/api/user/pinned-boards", {
            method: "POST", headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ boardId, isPinned })
        });
    };

    return (
        <div className="bg-wos-surface rounded-xl border border-white/5 overflow-hidden shadow-lg">
            <div className="p-3 bg-white/5 font-bold text-white border-b border-white/5 flex justify-between items-center">
                <span>Quick Menu</span>
                {session && (
                    <button onClick={() => setIsModalOpen(true)} className="text-slate-400 hover:text-ice-400 transition-colors" title="Add Board">
                        <Plus size={16} />
                    </button>
                )}
            </div>
            <div className="flex flex-col text-sm">
                {/* Pinned Boards */}
                {pinnedBoards.map(board => (
                    <div key={board.id} className="relative group border-b border-white/5">
                        <Link
                            href={board.allianceId ? `/alliance/${board.allianceId}/boards/${board.slug}` : `/boards/${board.slug}`}
                            className="block p-3 hover:bg-white/5 flex justify-between items-center text-slate-300 hover:text-ice-400 transition-colors"
                        >
                            <span className="truncate">📄 {board.title}</span>
                        </Link>
                        <button
                            onClick={(e) => { e.preventDefault(); togglePin(board.id, false); }}
                            className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-600 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all p-1"
                            title="Unpin"
                        >
                            <X size={12} />
                        </button>
                    </div>
                ))}

                {/* Default Static Items */}
                <Link href="/alliances" className="p-3 hover:bg-white/5 border-b border-white/5 flex justify-between text-slate-300 hover:text-ice-400">
                    <span>🛡️ Find Alliance</span>
                </Link>
                <Link href="/calendar" className="p-3 hover:bg-white/5 border-b border-white/5 flex justify-between text-slate-300 hover:text-ice-400">
                    <span>📅 Event Calendar</span>
                </Link>

                {!session && <div className="p-3 text-xs text-slate-500 text-center">Login to pin boards</div>}
            </div>

            {/* Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
                    <div className="bg-slate-800 rounded-xl border border-slate-700 w-full max-w-sm shadow-2xl overflow-hidden">
                        <div className="p-4 border-b border-slate-700 flex justify-between items-center bg-slate-900/50">
                            <h3 className="font-bold text-white">Pin Global Boards</h3>
                            <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-white"><X size={20} /></button>
                        </div>
                        <div className="max-h-[300px] overflow-y-auto p-2 space-y-1 bg-slate-800">
                            {loading ? <div className="p-4 text-center text-slate-500">Loading...</div> :
                                allGlobalBoards.map(board => {
                                    const isPinned = pinnedBoards.some(pb => pb.id === board.id);
                                    return (
                                        <button
                                            key={board.id}
                                            onClick={() => togglePin(board.id, !isPinned)}
                                            className={`w-full text-left p-2 rounded flex items-center justify-between transition-colors ${isPinned ? "bg-sky-500/10 border border-sky-500/30 text-sky-400" : "hover:bg-slate-700 text-slate-300"}`}
                                        >
                                            <span>{board.title}</span>
                                            {isPinned ? <Pin size={14} className="fill-current" /> : <Plus size={14} />}
                                        </button>
                                    );
                                })}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import { useEditor, EditorContent } from '@tiptap/react';
import { useEffect, useState } from 'react';
import StarterKit from '@tiptap/starter-kit';
import Underline from '@tiptap/extension-underline';
import Link from '@tiptap/extension-link';
import Image from '@tiptap/extension-image';
import Placeholder from '@tiptap/extension-placeholder';
import { Bold, Italic, Underline as UnderlineIcon, Strikethrough, Code, Quote, List, ListOrdered, Link as LinkIcon, Undo, Redo, Image as ImageIcon } from 'lucide-react';

interface RichEditorProps {
    content: string;
    onChange: (html: string) => void;
    placeholder?: string;
    onImageUpload?: (file: File) => Promise<string | null>;
}

export default function RichEditor({ content, onChange, placeholder = "Write something...", onImageUpload }: RichEditorProps) {
    const [isUploading, setIsUploading] = useState(false);

    const editor = useEditor({
        extensions: [
            StarterKit,
            Underline,
            Image.configure({
                HTMLAttributes: {
                    class: 'rounded-lg max-h-[500px] border border-slate-700',
                },
            }),
            Link.configure({
                openOnClick: false,
                HTMLAttributes: {
                    class: 'text-ice-400 underline cursor-pointer hover:text-ice-300',
                },
            }),
            Placeholder.configure({
                placeholder,
            })
        ],
        content: content,
        editorProps: {
            attributes: {
                class: `prose prose-invert prose-sm sm:prose-base lg:prose-lg xl:prose-xl focus:outline-none min-h-[300px] p-6 text-slate-200 ${isUploading ? 'opacity-50 cursor-wait' : ''}`,
            },
            handleDrop: (view, event, slice, moved) => {
                if (!moved && event.dataTransfer && event.dataTransfer.files && event.dataTransfer.files[0]) {
                    const file = event.dataTransfer.files[0];
                    if (file.type.startsWith('image/') && onImageUpload) {
                        event.preventDefault();
                        setIsUploading(true);
                        onImageUpload(file).then(url => {
                            if (url) {
                                const { schema } = view.state;
                                const coordinates = view.posAtCoords({ left: event.clientX, top: event.clientY });
                                if (coordinates) {
                                    const node = schema.nodes.image.create({ src: url });
                                    const transaction = view.state.tr.insert(coordinates.pos, node);
                                    view.dispatch(transaction);
                                }
                            }
                            setIsUploading(false);
                        }).catch(() => setIsUploading(false));
                        return true;
                    }
                }
                return false;
            }
        },
        onUpdate: ({ editor }) => {
            onChange(editor.getHTML());
        },
        immediatelyRender: false,
    });

    // Update editor content if prop changes (external update like image upload)
    useEffect(() => {
        if (editor && content !== editor.getHTML()) {
            editor.commands.setContent(content);
        }
    }, [content, editor]);

    if (!editor) {
        return null;
    }

    const setLink = () => {
        const previousUrl = editor.getAttributes('link').href;
        const url = window.prompt('URL', previousUrl);

        if (url === null) return;
        if (url === '') {
            editor.chain().focus().extendMarkRange('link').unsetLink().run();
            return;
        }

        editor.chain().focus().extendMarkRange('link').setLink({ href: url }).run();
    };

    interface ToolbarButtonProps {
        onClick: () => void;
        isActive?: boolean;
        disabled?: boolean;
        children: React.ReactNode;
        title: string;
    }

    const ToolbarButton = ({ onClick, isActive, disabled, children, title }: ToolbarButtonProps) => (
        <button
            onClick={(e) => { e.preventDefault(); onClick(); }}
            disabled={disabled}
            title={title}
            className={`p-2 rounded transition-colors ${isActive ? 'bg-ice-600 text-white' : 'text-slate-400 hover:bg-slate-700 hover:text-white'} ${disabled ? 'opacity-30 cursor-not-allowed' : ''}`}
        >
            {children}
        </button>
    );

    return (
        <div className="flex flex-col border border-slate-700 rounded-lg overflow-hidden bg-slate-900/30">
            {/* Toolbar */}
            <div className="flex flex-wrap items-center gap-1 p-2 bg-slate-800/80 border-b border-slate-700">
                <ToolbarButton
                    onClick={() => editor.chain().focus().toggleBold().run()}
                    isActive={editor.isActive('bold')}
                    title="Bold"
                >
                    <Bold size={18} />
                </ToolbarButton>
                <ToolbarButton
                    onClick={() => editor.chain().focus().toggleItalic().run()}
                    isActive={editor.isActive('italic')}
                    title="Italic"
                >
                    <Italic size={18} />
                </ToolbarButton>
                <ToolbarButton
                    onClick={() => editor.chain().focus().toggleUnderline().run()}
                    isActive={editor.isActive('underline')}
                    title="Underline"
                >
                    <UnderlineIcon size={18} />
                </ToolbarButton>
                <ToolbarButton
                    onClick={() => editor.chain().focus().toggleStrike().run()}
                    isActive={editor.isActive('strike')}
                    title="Strike"
                >
                    <Strikethrough size={18} />
                </ToolbarButton>

                <div className="w-px h-6 bg-slate-600 mx-1" />

                <ToolbarButton
                    onClick={() => editor.chain().focus().toggleCode().run()}
                    isActive={editor.isActive('code')}
                    title="Code"
                >
                    <Code size={18} />
                </ToolbarButton>
                <ToolbarButton
                    onClick={() => editor.chain().focus().toggleBlockquote().run()}
                    isActive={editor.isActive('blockquote')}
                    title="Quote"
                >
                    <Quote size={18} />
                </ToolbarButton>
                <ToolbarButton
                    onClick={setLink}
                    isActive={editor.isActive('link')}
                    title="Link"
                >
                    <LinkIcon size={18} />
                </ToolbarButton>
                <ToolbarButton
                    onClick={() => {
                        const url = window.prompt('Image URL');
                        if (url) editor.chain().focus().setImage({ src: url }).run();
                    }}
                    isActive={editor.isActive('image')}
                    title="Image URL"
                >
                    <ImageIcon size={18} />
                </ToolbarButton>

                <div className="w-px h-6 bg-slate-600 mx-1" />

                <ToolbarButton
                    onClick={() => editor.chain().focus().toggleBulletList().run()}
                    isActive={editor.isActive('bulletList')}
                    title="Bullet List"
                >
                    <List size={18} />
                </ToolbarButton>
                <ToolbarButton
                    onClick={() => editor.chain().focus().toggleOrderedList().run()}
                    isActive={editor.isActive('orderedList')}
                    title="Ordered List"
                >
                    <ListOrdered size={18} />
                </ToolbarButton>

                <div className="flex-1" />

                <ToolbarButton
                    onClick={() => editor.chain().focus().undo().run()}
                    disabled={!editor.can().undo()}
                    title="Undo"
                >
                    <Undo size={18} />
                </ToolbarButton>
                <ToolbarButton
                    onClick={() => editor.chain().focus().redo().run()}
                    disabled={!editor.can().redo()}
                    title="Redo"
                >
                    <Redo size={18} />
                </ToolbarButton>
            </div>

            {/* Editor */}
            <div className="bg-slate-900/30 min-h-[300px]">
                <EditorContent editor={editor} />
            </div>
        </div>
    );
}

export async function register() {
    if (process.env.NEXT_RUNTIME === 'nodejs') {
        // Prevent double execution in dev mode (hot reload)
        if ((global as any).__SCHEDULER_STARTED__) return;
        (global as any).__SCHEDULER_STARTED__ = true;

        console.log("⏰ Event Notification Scheduler Started");

        // Dynamic import to avoid build-time issues if any
        const { prisma } = await import("@/lib/prisma");
        const { sendPushNotification } = await import("@/lib/push");

        // Run every minute
        setInterval(async () => {
            const now = new Date();
            const nowTime = now.getTime();

            // Define windows (in ms)
            // 5 minutes before: [now + 5m, now + 5m + 59s]
            // We want to catch events starting roughly X minutes from now.
            // Since we run every minute, checking a 1-minute window is safe.

            const minutesToCheck = [1, 2, 5];

            for (const min of minutesToCheck) {
                const targetStart = new Date(nowTime + min * 60 * 1000);
                const targetEnd = new Date(nowTime + min * 60 * 1000 + 59 * 1000); // 1 minute window

                const events = await prisma.event.findMany({
                    where: {
                        startTime: {
                            gte: targetStart,
                            lt: targetEnd
                        }
                    },
                    include: {
                        subscriptions: true, // Get users who subscribed
                        alliance: { select: { name: true } }
                    }
                });

                for (const event of events) {
                    const timeLabel = `${min} minute${min > 1 ? 's' : ''}`;

                    for (const sub of event.subscriptions) {
                        try {
                            await sendPushNotification(sub.userId, {
                                title: `📢 ${event.title} starting in ${timeLabel}!`,
                                message: `Event in ${event.alliance.name} is starting soon. Get ready!`,
                                url: `/alliances/${event.allianceId}`
                            });
                        } catch (e) {
                            console.error(`Failed to notify user ${sub.userId}`, e);
                        }
                    }
                }
            }

            // --- Reservation Checks (5 minutes only) ---
            const resTargetStart = new Date(nowTime + 5 * 60 * 1000);
            const resTargetEnd = new Date(nowTime + 5 * 60 * 1000 + 59 * 1000);

            // 1. Construction
            const constructionRes = await prisma.constructionReservation.findMany({
                where: { startTime: { gte: resTargetStart, lt: resTargetEnd } },
                include: { alliance: { select: { name: true, id: true } } }
            });

            for (const res of constructionRes) {
                try {
                    await sendPushNotification(res.userId, {
                        title: `🏗️ Construction in 5 minutes!`,
                        message: `Your reservation at ${res.alliance.name} is starting soon.`,
                        url: `/alliances/${res.alliance.id}`
                    });
                } catch (e) { console.error("Push Error (Construction)", e); }
            }

            // 2. Training
            const trainingRes = await prisma.trainingReservation.findMany({
                where: { startTime: { gte: resTargetStart, lt: resTargetEnd } },
                include: { alliance: { select: { name: true, id: true } } }
            });

            for (const res of trainingRes) {
                try {
                    await sendPushNotification(res.userId, {
                        title: `⚔️ Training in 5 minutes!`,
                        message: `Your training slot at ${res.alliance.name} is starting soon.`,
                        url: `/alliances/${res.alliance.id}`
                    });
                } catch (e) { console.error("Push Error (Training)", e); }
            }

        }, 60 * 1000); // Check every 60 seconds
    }
}

export enum SecurityEventType {
    AUTH_FAILURE = "AUTH_FAILURE",
    UNAUTHORIZED_ACCESS = "UNAUTHORIZED_ACCESS",
    RATE_LIMIT_EXCEEDED = "RATE_LIMIT_EXCEEDED",
    SENSITIVE_ACTION = "SENSITIVE_ACTION"
}

export function logSecurityEvent(type: SecurityEventType, details: any) {
    // In production, send this to a dedicated logging service (Datadog, Sentry, CloudWatch)
    // For now, structured console logging.
    const timestamp = new Date().toISOString();
    console.warn(JSON.stringify({
        level: "SECURITY",
        timestamp,
        type,
        ...details
    }));
}

